206		installed := setup.HasAllHooks(settings)
207		binaryPath := resolveBinaryPath()
208		needsUpgrade := setup.HooksNeedUpgrade(settings, binaryPath)
209		needsDedupe := setup.HooksNeedDedupe(settings)
210	
211		if opts.status {
212			return handleClaudeStatus(cmd, installed, needsUpgrade, needsDedupe, displayPath, settingsPath, opts.jsonOut)
213		}
214		if opts.uninstall {
215			return handleClaudeUninstall(cmd, settings, settingsPath, installed, displayPath, opts.jsonOut)
216		}
217		if opts.dryRun {
218			return handleClaudeDryRun(cmd, installed, needsUpgrade, needsDedupe, displayPath, opts.jsonOut)
219		}
220		return handleClaudeInstall(cmd, settings, settingsPath, installed, needsUpgrade, needsDedupe, binaryPath, displayPath, opts.jsonOut)
221	}
