332	func handleClaudeInstall(cmd *cobra.Command, settings map[string]any, settingsPath string, installed bool, needsUpgrade bool, needsDedupe bool, binaryPath string, displayPath string, jsonOut bool) error {
333		if installed && !needsUpgrade && !needsDedupe {
334			return printClaudeResult(cmd, displayPath, "unchanged", jsonOut)
335		}
336	
337		setup.AddAllHooks(settings, binaryPath)
338		if err := setup.WriteClaudeSettings(settingsPath, settings); err != nil {
339			return fmt.Errorf("write settings: %w", err)
340		}
341	
342		action := hookActionPastTense[hookAction(installed, needsUpgrade, needsDedupe)]
343		return printClaudeResult(cmd, displayPath, action, jsonOut)
344	}
