341	// emitWindowsSearchNotice prints a one-time notice about keyword-only mode
342	// on Windows. Uses a marker file in the cache directory to avoid repeating.
343	func emitWindowsSearchNotice(repoRoot string) {
344		marker := filepath.Join(repoRoot, ".claude", ".cache", ".windows-search-notice")
345		if _, err := os.Stat(marker); err == nil {
346			return // already shown
347		}
348		fmt.Fprintln(os.Stderr, "[keyword-only mode: semantic search unavailable on this platform]")
349		_ = os.MkdirAll(filepath.Dir(marker), 0o755)
350		_ = os.WriteFile(marker, []byte("shown"), 0o644)
