353	// getOrStartEmbedder connects to the embed daemon, starting it if needed.
354	// Returns (nil, noopClose) if the daemon binary or model files are unavailable.
355	// The caller should defer the returned closer to release the connection.
356	func getOrStartEmbedder(repoRoot string) (search.Embedder, func()) {
357		// Fast path: try connecting to an already-running daemon
358		sockPath := embed.SocketPath(repoRoot)
359		client, err := embed.NewClient(sockPath, 500*time.Millisecond)
360		if err == nil {
361			resp, err := client.Health()
362			if err == nil && resp.Status == "ok" {
363				return &embedderAdapter{client: client}, func() { client.Close() }
364			}
365			client.Close()
366		}
367	
368		// Slow path: find model files and start daemon via EnsureDaemon
369		modelPath, tokenizerPath := embed.FindModelFiles(repoRoot)
370		if modelPath == "" || tokenizerPath == "" {
371			return nil, noopClose
372		}
373	
374		client, err = embed.EnsureDaemon(repoRoot, modelPath, tokenizerPath)
375		if err != nil {
376			if !errors.Is(err, embed.ErrNotSupported) {
377				slog.Warn("embed daemon failed, falling back to keyword search", "error", err)
378			}
379			return nil, noopClose
380		}
381		return &embedderAdapter{client: client}, func() { client.Close() }
382	}
