197	// EnsureGitignore creates or updates .claude/.gitignore with required patterns.
198	func EnsureGitignore(repoRoot string) error {
199		gitignorePath := filepath.Join(repoRoot, ".claude", ".gitignore")
200	
201		// Ensure directory exists
202		if err := os.MkdirAll(filepath.Dir(gitignorePath), 0755); err != nil {
203			return err
204		}
205	
206		marker := "# compound-agent managed"
207		patterns := marker + `
208	.cache/
209	*.sqlite
210	*.sqlite-shm
211	*.sqlite-wal
212	.ca-phase-state.json
213	.ca-failure-state.json
214	.ca-read-state.json
215	.ca-hints-shown
216	skills/compound/skills_index.json
217	`
218	
219		// If gitignore exists, check for our marker
220		existing, err := os.ReadFile(gitignorePath)
221		if err == nil {
222			if strings.Contains(string(existing), marker) {
223				return nil // Already has our patterns
224			}
225			// Append our patterns to existing content
226			combined := strings.TrimRight(string(existing), "\n") + "\n" + patterns
227			return os.WriteFile(gitignorePath, []byte(combined), 0644)
228		}
229		if !os.IsNotExist(err) {
230			return fmt.Errorf("read .gitignore: %w", err)
231		}
232	
233		return os.WriteFile(gitignorePath, []byte(patterns), 0644)
234	}
