301	func handleClaudeDryRun(cmd *cobra.Command, installed bool, needsUpgrade bool, needsDedupe bool, displayPath string, jsonOut bool) error {
302		action := hookAction(installed, needsUpgrade, needsDedupe)
303	
304		if jsonOut {
305			return writeJSON(cmd, map[string]any{
306				"dryRun":       true,
307				"location":     displayPath,
308				"action":       action,
309				"installed":    installed,
310				"needsUpgrade": needsUpgrade,
311				"needsDedupe":  needsDedupe,
312			})
313		}
314	
315		cmd.Println("[dry-run] Claude Code hooks analysis:")
316		cmd.Printf("  Settings file: %s\n", displayPath)
317		cmd.Printf("  Currently installed: %v\n", installed)
318		if action == "unchanged" {
319			cmd.Println("  Action: no changes needed")
320		} else {
321			cmd.Printf("  Action would: %s\n", action)
322		}
323		if needsUpgrade {
324			cmd.Println("  Upgrade: npx hooks would be upgraded to binary path")
325		}
326		if needsDedupe {
327			cmd.Println("  Deduplicate: duplicate hook entries would be removed")
328		}
329		return nil
330	}
