450	// printDoctorResults renders doctor check results to the command output.
451	func printDoctorResults(cmd *cobra.Command, checks []doctorCheck) {
452		passCount, failCount, warnCount, infoCount := 0, 0, 0, 0
453		for _, c := range checks {
454			icon := "[ok]"
455			switch c.Status {
456			case "fail":
457				icon = "[fail]"
458				failCount++
459			case "warn":
460				icon = "[warn]"
461				warnCount++
462			case "info":
463				icon = "[info]"
464				infoCount++
465			default:
466				passCount++
467			}
468			cmd.Printf("  %s %s\n", icon, c.Name)
469			if c.Fix != "" {
470				cmd.Printf("       Fix: %s\n", c.Fix)
471			}
472		}
473		cmd.Println()
474		if infoCount > 0 {
475			cmd.Printf("Results: %d passed, %d failed, %d warnings, %d info\n", passCount, failCount, warnCount, infoCount)
476		} else {
477			cmd.Printf("Results: %d passed, %d failed, %d warnings\n", passCount, failCount, warnCount)
478		}
479	}
480	
481	type doctorCheck struct {
482		Name   string `json:"name"`
483		Status string `json:"status"` // "pass", "fail", "warn", "info"
484		Fix    string `json:"fix,omitempty"`
485	}
