589			}
590		}
591	
592		if !bdInstalled {
593			cmd.Println("  Beads: not installed")
594			cmd.Println("         Install: curl -sSL https://raw.githubusercontent.com/steveyegge/beads/main/scripts/install.sh | bash")
595			return
596		}
597	
598		// Check if .beads/ is initialized in this repo
599		if _, err := os.Stat(filepath.Join(repoRoot, ".beads")); err == nil {
600			cmd.Println("  Beads: initialized")
601		} else {
602			cmd.Println("  Beads: installed but not initialized in this repo")
603			cmd.Println("         Run: bd init")
604		}
