102	// normalizeDocDate replaces last-updated date values with a fixed string
103	// so that date-only differences don't trigger spurious template updates.
104	func normalizeDocDate(content string) string {
105		return docDatePattern.ReplaceAllString(content, `last-updated: "NORMALIZED"`)
