252	// InstallDocTemplates writes documentation .md files to docs/compound/.
253	// Substitutes {{VERSION}}, {{DATE}}, and quality gate placeholders.
254	// Creates missing and updates stale files (date-only changes are ignored).
255	// Returns (created, updated, error).
256	func InstallDocTemplates(repoRoot string, version string, stack StackInfo) (int, int, error) {
257		dir := filepath.Join(repoRoot, "docs", "compound")
258		if err := os.MkdirAll(dir, 0755); err != nil {
259			return 0, 0, fmt.Errorf("mkdir %s: %w", dir, err)
260		}
261	
262		created, updated := 0, 0
263		date := time.Now().Format("2006-01-02")
264		for filename, tmpl := range templates.DocTemplates() {
265			filePath := filepath.Join(dir, filename)
266			content := strings.ReplaceAll(tmpl, "{{VERSION}}", version)
267			content = strings.ReplaceAll(content, "{{DATE}}", date)
268			content = substituteQualityGates(content, stack)
269	
270			existing, err := os.ReadFile(filePath)
271			if errors.Is(err, os.ErrNotExist) {
272				if wErr := os.WriteFile(filePath, []byte(content), 0644); wErr != nil {
273					return created, updated, fmt.Errorf("write %s: %w", filePath, wErr)
274				}
275				created++
276				continue
277			}
278			if err != nil {
279				return created, updated, fmt.Errorf("read %s: %w", filePath, err)
280			}
281			// Compare with date normalization to avoid spurious updates
282			if normalizeDocDate(string(existing)) != normalizeDocDate(content) {
283				if wErr := os.WriteFile(filePath, []byte(content), 0644); wErr != nil {
284					return created, updated, fmt.Errorf("write %s: %w", filePath, wErr)
285				}
286				updated++
287			}
288		}
289		return created, updated, nil
290	}
