375	// Substitutes {{VERSION}} placeholder. Creates if missing, updates if version differs.
376	// Returns (created, updated, error).
377	func CreatePluginManifest(repoRoot string, version string) (bool, bool, error) {
378		pluginPath := filepath.Join(repoRoot, ".claude", "plugin.json")
379	
380		if err := os.MkdirAll(filepath.Join(repoRoot, ".claude"), 0755); err != nil {
381			return false, false, fmt.Errorf("mkdir .claude: %w", err)
382		}
383	
384		content := strings.ReplaceAll(templates.PluginJSON(), "{{VERSION}}", version)
385	
386		existing, readErr := os.ReadFile(pluginPath)
387		if readErr != nil && !errors.Is(readErr, os.ErrNotExist) {
388			return false, false, fmt.Errorf("read plugin.json: %w", readErr)
389		}
390	
391		if errors.Is(readErr, os.ErrNotExist) {
392			// File doesn't exist — create
393			return true, false, os.WriteFile(pluginPath, []byte(content), 0644)
394		}
395	
396		// File exists — check if version matches
397		var manifest map[string]any
398		if err := json.Unmarshal(existing, &manifest); err == nil {
399			if manifest["version"] == version {
400				return false, false, nil // Already up to date
401			}
402		}
403	
404		// Version mismatch or unparseable — update
405		return false, true, os.WriteFile(pluginPath, []byte(content), 0644)
406	}
