408	// PruneStaleTemplates removes managed files and directories that no longer
409	// exist in the current template set. Only touches compound/ namespaces.
410	// Returns count of items removed.
411	func pruneFlatDirs(repoRoot string) (int, error) {
412		pruned := 0
413		flatDirs := []struct {
414			dir      string
415			expected map[string]string
416		}{
417			{filepath.Join(repoRoot, ".claude", "agents", "compound"), templates.AgentTemplates()},
418			{filepath.Join(repoRoot, ".claude", "commands", "compound"), templates.CommandTemplates()},
419			{filepath.Join(repoRoot, "docs", "compound"), templates.DocTemplates()},
420		}
421		for _, fd := range flatDirs {
422			n, err := pruneStaleFiles(fd.dir, fd.expected)
423			if err != nil {
424				return pruned, err
425			}
426			pruned += n
427		}
428		return pruned, nil
