574	// pruneDir handles pruning of a directory entry. Returns (pruned count, error).
575	func pruneDir(root, relPath string, expectedDirs map[string]bool, expectedFiles map[string]bool, skipTopLevel map[string]bool) (int, error) {
576		if !expectedDirs[relPath] {
577			if err := os.RemoveAll(filepath.Join(root, filepath.FromSlash(relPath))); err != nil {
578				return 0, fmt.Errorf("remove %s: %w", relPath, err)
579			}
580			return 1, nil
581		}
582		return pruneManagedSubtree(root, relPath, expectedFiles, expectedDirs, skipTopLevel)
583	}
584	
585	// pruneManagedSubtree removes files and directories below root that are not in
586	// the expected sets. Relative paths in expectedFiles/expectedDirs use slash
587	// separators. skipTopLevel names are preserved only at the root level.
588	func pruneManagedSubtree(
589		root string,
590		relDir string,
591		expectedFiles map[string]bool,
592		expectedDirs map[string]bool,
593		skipTopLevel map[string]bool,
594	) (int, error) {
595		dirPath := root
596		if relDir != "" {
597			dirPath = filepath.Join(root, filepath.FromSlash(relDir))
598		}
599	
600		entries, err := os.ReadDir(dirPath)
601		if err != nil {
602			if errors.Is(err, os.ErrNotExist) {
603				return 0, nil
604			}
605			return 0, fmt.Errorf("read %s: %w", dirPath, err)
606		}
607	
608		pruned := 0
609		for _, entry := range entries {
610			n, entryErr := pruneEntry(root, relDir, entry, expectedFiles, expectedDirs, skipTopLevel)
611			if entryErr != nil {
612				return pruned, entryErr
613			}
614			pruned += n
615		}
616	
617		return pruned, nil
618	}
619	
620	// pruneEntry processes a single directory entry for pruning.
621	func pruneEntry(
622		root, relDir string,
623		entry os.DirEntry,
624		expectedFiles, expectedDirs map[string]bool,
625		skipTopLevel map[string]bool,
626	) (int, error) {
627		relPath := entry.Name()
628		if relDir != "" {
629			relPath = path.Join(relDir, entry.Name())
630		}
631	
632		if shouldSkipEntry(entry, relDir, relPath, skipTopLevel) {
633			return 0, nil
634		}
635	
636		if entry.IsDir() {
637			return pruneDir(root, relPath, expectedDirs, expectedFiles, skipTopLevel)
638		}
639	
640		if !expectedFiles[relPath] {
641			if err := os.Remove(filepath.Join(root, filepath.FromSlash(relPath))); err != nil {
642				return 0, fmt.Errorf("remove %s: %w", relPath, err)
643			}
644			return 1, nil
645		}
646		return 0, nil
647	}
648	
649	// pruneStaleSubdirs removes subdirectories from dir that are not in the expected map (by key).
650	// skip contains directory names to always preserve (e.g., "agents" within skills/compound/).
651	// Returns count of directories removed.
652	func pruneStaleSubdirs(dir string, expected map[string]string, skip []string) (int, error) {
653		entries, err := os.ReadDir(dir)
654		if err != nil {
655			if errors.Is(err, os.ErrNotExist) {
656				return 0, nil
657			}
658			return 0, fmt.Errorf("read %s: %w", dir, err)
659		}
660		skipSet := make(map[string]bool, len(skip))
661		for _, s := range skip {
662			skipSet[s] = true
663		}
664		pruned := 0
665		for _, entry := range entries {
666			if !entry.IsDir() {
667				continue
668			}
669			if skipSet[entry.Name()] {
670				continue
671			}
672			if _, ok := expected[entry.Name()]; !ok {
673				if rErr := os.RemoveAll(filepath.Join(dir, entry.Name())); rErr != nil {
674					return pruned, fmt.Errorf("remove %s: %w", entry.Name(), rErr)
675				}
676				pruned++
677			}
678		}
679		return pruned, nil
680	}
681	
682	// installMapToDir writes files from a map to a directory.
683	// Creates missing files and updates existing files whose content has changed.
684	// Returns (created count, updated count, error).
685	func installMapToDir(dir string, files map[string]string) (int, int, error) {
686		if err := os.MkdirAll(dir, 0755); err != nil {
687			return 0, 0, fmt.Errorf("mkdir %s: %w", dir, err)
688		}
689	
690		created, updated := 0, 0
691		for filename, content := range files {
692			filePath := filepath.Join(dir, filename)
693			c, u, err := reconcileFile(filePath, content)
694			if err != nil {
695				return created, updated, err
696			}
697			if c {
698				created++
699			}
700			if u {
701				updated++
702			}
703		}
704		return created, updated, nil
705	}
