1	package setup
2	
3	import (
4		"os"
5		"path/filepath"
6	)
7	
8	// FallbackTestCmd is used when no project stack can be detected.
9	const FallbackTestCmd = "detect and run the project's test suite"
10	
11	// FallbackLintCmd is used when no project stack can be detected.
12	const FallbackLintCmd = "detect and run the project's linter"
13	
14	// FallbackBuildCmd is used when no build/package verification command can be
15	// confidently detected.
16	const FallbackBuildCmd = "detect and run the project's build/package verification when the verification contract requires it"
17	
18	// StackInfo holds the detected quality gate commands for a project.
19	type StackInfo struct {
20		TestCmd  string
21		LintCmd  string
22		BuildCmd string
23	}
24	
25	// withFallbacks fills empty command fields with descriptive fallback guidance.
26	func (s StackInfo) withFallbacks() StackInfo {
27		if s.TestCmd == "" {
28			s.TestCmd = FallbackTestCmd
29		}
30		if s.LintCmd == "" {
31			s.LintCmd = FallbackLintCmd
32		}
33		if s.BuildCmd == "" {
34			s.BuildCmd = FallbackBuildCmd
35		}
36		return s
37	}
38	
39	// DetectStack inspects repoRoot for language marker files and returns
40	// the appropriate test, lint, and build/package verification commands.
41	// Priority: Go > Rust > Python > Node > Makefile.
42	func DetectStack(repoRoot string) StackInfo {
43		if fileExists(repoRoot, "go.mod") {
44			return StackInfo{
45				TestCmd:  "go test ./...",
46				LintCmd:  "golangci-lint run ./...",
47				BuildCmd: "go build ./...",
48			}
49		}
50		if fileExists(repoRoot, "Cargo.toml") {
51			return StackInfo{
52				TestCmd:  "cargo test",
53				LintCmd:  "cargo clippy",
54				BuildCmd: "cargo build",
55			}
56		}
57		if fileExists(repoRoot, "pyproject.toml") || fileExists(repoRoot, "setup.py") {
58			return StackInfo{
59				TestCmd:  "pytest",
60				LintCmd:  "ruff check .",
61				BuildCmd: "python -m compileall .",
62			}
63		}
64		if fileExists(repoRoot, "package.json") {
65			return detectNodePackageManager(repoRoot)
66		}
67		if fileExists(repoRoot, "Makefile") {
68			return StackInfo{
69				TestCmd:  "make test",
70				LintCmd:  "make lint",
71				BuildCmd: "make build",
72			}
73		}
74		return StackInfo{
75			TestCmd:  FallbackTestCmd,
76			LintCmd:  FallbackLintCmd,
77			BuildCmd: FallbackBuildCmd,
78		}
79	}
80	
81	// detectNodePackageManager determines the Node package manager from lockfiles.
82	func detectNodePackageManager(repoRoot string) StackInfo {
83		if fileExists(repoRoot, "pnpm-lock.yaml") {
84			return StackInfo{
85				TestCmd:  "pnpm test",
86				LintCmd:  "pnpm lint",
87				BuildCmd: "pnpm build",
88			}
89		}
90		if fileExists(repoRoot, "yarn.lock") {
91			return StackInfo{
92				TestCmd:  "yarn test",
93				LintCmd:  "yarn lint",
94				BuildCmd: "yarn build",
95			}
96		}
97		if fileExists(repoRoot, "bun.lock") || fileExists(repoRoot, "bun.lockb") {
98			return StackInfo{
99				TestCmd:  "bun test",
100				LintCmd:  "bun run lint",
101				BuildCmd: "bun run build",
102			}
103		}
104		// Default to npm (package-lock.json or no lockfile)
105		return StackInfo{
106			TestCmd:  "npm test",
107			LintCmd:  "npm run lint",
108			BuildCmd: "npm run build",
109		}
110	}
111	
112	// fileExists checks whether a regular file (not a directory) exists at repoRoot/name.
113	func fileExists(repoRoot, name string) bool {
114		info, err := os.Stat(filepath.Join(repoRoot, name))
115		return err == nil && !info.IsDir()
116	}
