152	// hookEntry creates a single hook configuration entry.
153	func hookEntry(matcher, command string) map[string]any {
154		return map[string]any{
155			"matcher": matcher,
156			"hooks": []any{
157				map[string]any{
158					"type":    "command",
159					"command": command,
160				},
161			},
162		}
163	}
