165	// getHooksMap retrieves or creates the hooks map in settings.
166	func getHooksMap(settings map[string]any) map[string]any {
167		if settings["hooks"] == nil {
168			settings["hooks"] = map[string]any{}
169		}
170		hooks, ok := settings["hooks"].(map[string]any)
171		if !ok {
172			hooks = map[string]any{}
173			settings["hooks"] = hooks
174		}
175		return hooks
