178	// getHookArray retrieves or creates a hook type array.
179	func getHookArray(hooks map[string]any, hookType string) []any {
180		if hooks[hookType] == nil {
181			hooks[hookType] = []any{}
182		}
183		arr, ok := hooks[hookType].([]any)
184		if !ok {
185			arr = []any{}
186			hooks[hookType] = arr
187		}
188		return arr
