218	func normalizeManagedCommand(cmd string) string {
219		trimmed := strings.TrimSpace(cmd)
220		if strings.HasPrefix(trimmed, "npx ca ") {
221			return "BIN " + strings.TrimPrefix(trimmed, "npx ca ")
222		}
223		if strings.HasPrefix(trimmed, "'") {
224			if end := strings.Index(trimmed[1:], "'"); end >= 0 {
225				return "BIN" + trimmed[end+2:]
226			}
227		}
228		if idx := strings.Index(trimmed, " "); idx >= 0 {
229			first := trimmed[:idx]
230			if first == "ca" || strings.HasSuffix(first, "/ca") {
231				return "BIN" + trimmed[idx:]
232			}
233		}
234		return trimmed
235	}
