237	func commandHasMarker(cmd, marker string) bool {
238		if strings.Contains(cmd, marker) {
239			return true
240		}
241		if strings.HasPrefix(marker, "BIN ") {
242			return strings.Contains(normalizeManagedCommand(cmd), marker)
243		}
244		return false
245	}
