248		hMap, ok := hook.(map[string]any)
249		if !ok {
250			return false
251		}
252		cmd, _ := hMap["command"].(string)
253		for _, marker := range markers {
254			if commandHasMarker(cmd, marker) {
255				return true
256			}
257		}
