261	func filterHookEntries(arr []any, markers []string) ([]any, int, string) {
262		filtered := make([]any, 0, len(arr))
263		matchCount := 0
264		firstCommand := ""
265	
266		for _, entry := range arr {
267			entryMap, ok := entry.(map[string]any)
268			if !ok {
269				filtered = append(filtered, entry)
270				continue
271			}
272			hooksList, ok := entryMap["hooks"].([]any)
273			if !ok {
274				filtered = append(filtered, entry)
275				continue
276			}
277	
278			keptHooks := make([]any, 0, len(hooksList))
279			removedAny := false
280			for _, hook := range hooksList {
281				if hookHasMarker(hook, markers) {
282					if firstCommand == "" {
283						hMap, _ := hook.(map[string]any)
284						firstCommand, _ = hMap["command"].(string)
285					}
286					matchCount++
287					removedAny = true
288					continue
289				}
290				keptHooks = append(keptHooks, hook)
291			}
292	
293			if !removedAny {
294				filtered = append(filtered, entry)
295				continue
296			}
297			if len(keptHooks) == 0 {
298				continue
299			}
300	
301			cloned := make(map[string]any, len(entryMap))
302			for key, value := range entryMap {
303				cloned[key] = value
304			}
305			cloned["hooks"] = keptHooks
306			filtered = append(filtered, cloned)
307		}
308	
309		return filtered, matchCount, firstCommand
310	}
