55	func GetPhaseState(repoRoot string) *PhaseState {
56		data, err := os.ReadFile(PhaseStatePath(repoRoot))
57		if err != nil {
58			return nil
59		}
60	
61		// First unmarshal into a raw map to handle legacy fields
62		var raw map[string]interface{}
63		if err := json.Unmarshal(data, &raw); err != nil {
64			return nil
65		}
