120			}
121		}
122		if time.Since(startedAt) > phaseStateMaxAge {
123			os.Remove(PhaseStatePath(repoRoot))
124			return false
125		}
126	
127		return true
128	}
129	
130	// UpdatePhaseState reads the current state, applies partial updates, and writes back.
131	func UpdatePhaseState(repoRoot string, partial map[string]interface{}) error {
132		state := GetPhaseState(repoRoot)
133		if state == nil {
134			return nil
135		}
136	
137		// Apply partial updates
138		if sr, ok := partial["skills_read"]; ok {
139			if skills, ok := sr.([]string); ok {
140				state.SkillsRead = skills
141			}
142		}
143		if gp, ok := partial["gates_passed"]; ok {
144			if gates, ok := gp.([]string); ok {
145				state.GatesPassed = gates
146			}
147		}
148	
149		data, err := json.MarshalIndent(state, "", "  ")
150		if err != nil {
151			return err
152		}
153		return os.WriteFile(PhaseStatePath(repoRoot), data, 0o644)
154	}
155	
156	// WritePhaseState writes the phase state to disk.
157	func WritePhaseState(repoRoot string, state *PhaseState) error {
158		data, err := json.MarshalIndent(state, "", "  ")
159		if err != nil {
160			return err
161		}
162		return os.WriteFile(PhaseStatePath(repoRoot), data, 0o644)
163	}
