190	// CleanPhaseStateIfFinal removes the phase state file if the "final" gate has been recorded.
191	func CleanPhaseStateIfFinal(repoRoot string) {
192		state := GetPhaseState(repoRoot)
193		if state == nil || !state.CookitActive {
194			return
195		}
196		for _, g := range state.GatesPassed {
197			if g == "final" {
198				if err := os.Remove(PhaseStatePath(repoRoot)); err != nil && !os.IsNotExist(err) {
199					slog.Warn("clean phase state failed", "error", err)
200				}
201				return
202			}
203		}
204	}
