206	// ExpectedGateForPhase returns the required gate name for a phase index, or "" for none.
207	func ExpectedGateForPhase(phaseIndex int) string {
208		switch phaseIndex {
209		case 2:
210			return "post-plan"
211		case 3:
212			return "gate-3"
213		case 4:
214			return "gate-4"
215		case 5:
216			return "final"
217		default:
218			return ""
219		}
