191	// hasHookMarker checks if any entry in the array contains any of the given markers.
192	func hasHookMarker(arr []any, markers []string) bool {
193		for _, entry := range arr {
194			entryMap, ok := entry.(map[string]any)
195			if !ok {
196				continue
197			}
198			hooksList, ok := entryMap["hooks"].([]any)
199			if !ok {
200				continue
201			}
202			for _, h := range hooksList {
203				hMap, ok := h.(map[string]any)
204				if !ok {
205					continue
206				}
207				cmd, _ := hMap["command"].(string)
208				for _, marker := range markers {
209					if commandHasMarker(cmd, marker) {
210						return true
211					}
212				}
213			}
214		}
215		return false
216	}
