312	// upgradeNpxHooks replaces "npx ca" commands with the direct binary path.
313	// This is needed because npx resolution fails in Claude Code hook contexts
314	// (different PATH/environment). Called when binaryPath is available.
315	func upgradeNpxHooks(hooks map[string]any, binaryPath string) {
316		if binaryPath == "" {
317			return
318		}
319		escaped := util.ShellEscape(binaryPath)
320		for _, hookType := range HookTypes {
321			arr := getHookArray(hooks, hookType)
322			for _, entry := range arr {
323				entryMap, ok := entry.(map[string]any)
324				if !ok {
325					continue
326				}
327				hooksList, ok := entryMap["hooks"].([]any)
328				if !ok {
329					continue
330				}
331				for _, h := range hooksList {
332					hMap, ok := h.(map[string]any)
333					if !ok {
334						continue
335					}
336					cmd, _ := hMap["command"].(string)
337					if strings.Contains(cmd, "npx ca ") {
338						upgraded := strings.Replace(cmd, "npx ca ", escaped+" ", 1)
339						hMap["command"] = upgraded
340					}
341				}
342			}
343		}
344	}
