346	// AddAllHooks adds all compound-agent hooks to settings.
347	// binaryPath can be empty string for npx fallback, or path to Go binary.
348	func AddAllHooks(settings map[string]any, binaryPath string) {
349		hooks := getHooksMap(settings)
350	
351		// Upgrade existing npx-based hooks to use direct binary path
352		upgradeNpxHooks(hooks, binaryPath)
353	
354		for _, spec := range managedHookSpecs {
355			arr := getHookArray(hooks, spec.hookType)
356			filtered, _, firstCommand := filterHookEntries(arr, spec.markers)
357			command := spec.buildCommand(binaryPath)
358			if binaryPath == "" && firstCommand != "" && !strings.Contains(firstCommand, "npx ca ") {
359				command = firstCommand
360			}
361			hooks[spec.hookType] = append(filtered, hookEntry(spec.matcher, command))
362		}
363	}
