365	// HasAllHooks checks if all required compound-agent hooks are installed.
366	func HasAllHooks(settings map[string]any) bool {
367		hooks, ok := settings["hooks"].(map[string]any)
368		if !ok {
369			return false
370		}
371	
372		for _, spec := range managedHookSpecs {
373			arr, ok := hooks[spec.hookType].([]any)
374			if !ok {
375				return false
376			}
377			if !hasHookMarker(arr, spec.markers) {
378				return false
379			}
380		}
381		return true
382	}
383	
384	// hookArrayHasNpx checks if any entry in a hook array contains npx commands.
385	func hookArrayHasNpx(arr []any) bool {
386		for _, entry := range arr {
387			entryMap, ok := entry.(map[string]any)
388			if !ok {
389				continue
390			}
391			hooksList, ok := entryMap["hooks"].([]any)
392			if !ok {
393				continue
394			}
395			for _, h := range hooksList {
396				hMap, ok := h.(map[string]any)
397				if !ok {
398					continue
399				}
400				cmd, _ := hMap["command"].(string)
401				if strings.Contains(cmd, "npx ca ") {
402					return true
403				}
404			}
405		}
406		return false
407	}
408	
409	// HooksNeedUpgrade returns true if hooks exist but use npx commands
410	// and a binary path is available for upgrade.
411	func HooksNeedUpgrade(settings map[string]any, binaryPath string) bool {
412		if binaryPath == "" {
413			return false
414		}
415		hooks, ok := settings["hooks"].(map[string]any)
416		if !ok {
417			return false
418		}
419		for _, hookType := range HookTypes {
420			arr, ok := hooks[hookType].([]any)
421			if !ok {
422				continue
423			}
424			if hookArrayHasNpx(arr) {
425				return true
426			}
427		}
428		return false
429	}
430	
431	// HooksNeedDedupe returns true if compound-agent hooks are duplicated and should be reconciled.
432	func HooksNeedDedupe(settings map[string]any) bool {
433		hooks, ok := settings["hooks"].(map[string]any)
434		if !ok {
435			return false
436		}
437		for _, spec := range managedHookSpecs {
438			arr, ok := hooks[spec.hookType].([]any)
439			if !ok {
440				continue
441			}
442			_, matchCount, _ := filterHookEntries(arr, spec.markers)
443			if matchCount > 1 {
444				return true
445			}
446		}
447		return false
448	}
449	
450	// isCompoundHookEntry returns true if the hook entry contains any compound-agent marker.
451	func isCompoundHookEntry(entry any) bool {
452		entryMap, ok := entry.(map[string]any)
453		if !ok {
454			return false
455		}
456		hooksList, ok := entryMap["hooks"].([]any)
457		if !ok {
458			return false
459		}
460		for _, h := range hooksList {
461			hMap, ok := h.(map[string]any)
462			if !ok {
463				continue
464			}
465			cmd, _ := hMap["command"].(string)
466			for _, marker := range HookMarkers {
467				if commandHasMarker(cmd, marker) {
468					return true
469				}
470			}
471		}
472		return false
473	}
474	
475	// removeHookEntries filters out compound-agent entries from a hook type array.
476	// Returns the filtered array and whether any entries were removed.
477	func removeHookEntries(arr []any) ([]any, bool) {
478		filtered := make([]any, 0, len(arr))
479		for _, entry := range arr {
480			if !isCompoundHookEntry(entry) {
481				filtered = append(filtered, entry)
482			}
483		}
484		return filtered, len(filtered) < len(arr)
485	}
486	
487	// RemoveAllHooks removes all compound-agent hooks from settings.
488	func RemoveAllHooks(settings map[string]any) bool {
489		hooks, ok := settings["hooks"].(map[string]any)
490		if !ok {
491			return false
492		}
493	
494		anyRemoved := false
495		for _, hookType := range HookTypes {
496			arr, ok := hooks[hookType].([]any)
497			if !ok {
498				continue
499			}
500			filtered, removed := removeHookEntries(arr)
501			if removed {
502				anyRemoved = true
503			}
504			hooks[hookType] = filtered
505		}
506	
507		return anyRemoved
508	}
