15	
16	func migrateFromTSCmd() *cobra.Command {
17		var (
18			repoRoot   string
19			binaryPath string
20			dryRun     bool
21		)
22	
23		cmd := &cobra.Command{
24			Use:   "migrate-from-ts",
25			Short: "Migrate from TypeScript compound-agent to Go binary",
26			RunE: func(cmd *cobra.Command, args []string) error {
27				if repoRoot == "" {
28					repoRoot = util.GetRepoRoot()
29				}
30				if binaryPath == "" {
31					binaryPath = resolveBinaryPath()
32				}
33	
34				return runMigration(cmd, repoRoot, binaryPath, dryRun)
35			},
36		}
37	
38		cmd.Flags().StringVar(&repoRoot, "repo-root", "", "Repository root (defaults to git root)")
39		cmd.Flags().StringVar(&binaryPath, "binary-path", "", "Path to Go binary (defaults to current executable)")
40		cmd.Flags().BoolVar(&dryRun, "dry-run", false, "Report what would be migrated without making changes")
41		return cmd
42	}
43	
44	// runMigration performs the TS-to-Go migration.
45	func runMigration(cmd *cobra.Command, repoRoot, binaryPath string, dryRun bool) error {
46		indexPath := filepath.Join(repoRoot, ".claude", "lessons", "index.jsonl")
47	
48		// Step 1: Detect TS installation
49		_, err := os.Stat(indexPath)
50		if os.IsNotExist(err) {
51			cmd.Println("No TS compound-agent installation found.")
52			cmd.Println("  Missing: .claude/lessons/index.jsonl")
53			cmd.Println("  Run 'ca init' to start fresh.")
54			return nil
55		}
56		if err != nil {
57			return fmt.Errorf("check index.jsonl: %w", err)
58		}
59	
60		// Step 2: Validate JSONL and count lessons
61		validCount, invalidCount, err := validateJSONL(indexPath)
62		if err != nil {
63			return fmt.Errorf("validate JSONL: %w", err)
64		}
65	
66		// Step 3: Check for npx-based hooks in settings
67		settingsPath := filepath.Join(repoRoot, ".claude", "settings.json")
68		npxHookCount := countNpxHooks(settingsPath)
69	
70		// Step 4: Report findings
71		cmd.Println("Migration Report")
72		cmd.Println("----------------------------------------")
73		cmd.Printf("  Lessons: %d lesson(s) found\n", validCount)
74		if invalidCount > 0 {
75			cmd.Printf("  Warnings: %d invalid line(s) in JSONL (will be skipped on read)\n", invalidCount)
76		}
77		if npxHookCount > 0 {
78			cmd.Printf("  Hooks: %d npx-based hook(s) to update\n", npxHookCount)
79		} else {
80			cmd.Println("  Hooks: no npx hooks found")
81		}
82	
83		if dryRun {
84			cmd.Println()
85			cmd.Println("[dry-run] No changes made. Remove --dry-run to apply migration.")
86			return nil
87		}
88	
89		// Step 5: Update hooks (replace npx with Go binary path)
90		if npxHookCount > 0 {
