103	// validateJSONL reads a JSONL file and returns counts of valid and invalid lines.
104	func validateJSONL(path string) (valid, invalid int, err error) {
105		f, err := os.Open(path)
106		if err != nil {
107			return 0, 0, err
108		}
109		defer f.Close()
110	
111		scanner := bufio.NewScanner(f)
112		scanner.Buffer(make([]byte, 0, 64*1024), 1024*1024)
113	
114		for scanner.Scan() {
115			line := strings.TrimSpace(scanner.Text())
116			if line == "" {
117				continue
118			}
119			var obj map[string]any
120			if err := json.Unmarshal([]byte(line), &obj); err != nil {
121				invalid++
122				continue
123			}
124			// Check it has at least an id field (minimal validation)
125			if _, hasID := obj["id"]; !hasID {
126				invalid++
127				continue
128			}
129			valid++
130		}
131	
132		if err := scanner.Err(); err != nil {
133			return valid, invalid, err
134		}
135		return valid, invalid, nil
136	}
