138	// countNpxHooks counts how many hook commands reference "npx ca" in settings.
139	func countNpxHooks(settingsPath string) int {
140		settings, err := setup.ReadClaudeSettings(settingsPath)
141		if err != nil {
142			return 0
143		}
144		hooks, ok := settings["hooks"].(map[string]any)
145		if !ok {
146			return 0
147		}
148	
149		count := 0
150		for _, hookType := range setup.HookTypes {
151			arr, ok := hooks[hookType].([]any)
152			if !ok {
153				continue
154			}
155			for _, entry := range arr {
156				count += countNpxInEntry(entry)
157			}
158		}
159		return count
160	}
161	
162	// countNpxInEntry counts npx-based hook commands within a single hook entry.
163	func countNpxInEntry(entry any) int {
164		entryMap, ok := entry.(map[string]any)
165		if !ok {
166			return 0
167		}
168		hooksList, ok := entryMap["hooks"].([]any)
169		if !ok {
170			return 0
171		}
172		count := 0
173		for _, h := range hooksList {
174			if isNpxHook(h) {
175				count++
176			}
177		}
178		return count
179	}
