181	// isNpxHook reports whether a hook map entry references an npx-based command.
182	func isNpxHook(h any) bool {
183		hMap, ok := h.(map[string]any)
184		if !ok {
185			return false
186		}
187		cmd, _ := hMap["command"].(string)
188		return strings.Contains(cmd, "npx ca ") || strings.Contains(cmd, "npx compound-agent")
189	}
