191	// migrateHooks reads settings.json, replaces npx-based commands with Go binary, and writes back.
192	func migrateHooks(settingsPath, binaryPath string) error {
193		settings, err := setup.ReadClaudeSettings(settingsPath)
194		if err != nil {
195			return err
196		}
197	
198		// Remove all existing compound-agent hooks, then re-add with Go binary path
199		setup.RemoveAllHooks(settings)
200		setup.AddAllHooks(settings, binaryPath)
201	
202		return setup.WriteClaudeSettings(settingsPath, settings)
203	}
