197	// readEmbedDir reads all files from an embedded FS directory into a map.
198	func readEmbedDir(fsys embed.FS, dir string) map[string]string {
199		result := make(map[string]string)
200		entries, err := fs.ReadDir(fsys, dir)
201		if err != nil {
202			return result
203		}
204		for _, entry := range entries {
205			if entry.IsDir() {
206				continue
207			}
208			data, readErr := fs.ReadFile(fsys, path.Join(dir, entry.Name()))
209			if readErr == nil {
210				result[entry.Name()] = string(data)
211			}
212		}
213		return result
214	}
