463	// addAllHooksForInfoTest creates a hook config that HasAllHooks recognizes.
464	func addAllHooksForInfoTest(settings map[string]any) {
465		hooks := map[string]any{}
466		specs := []struct {
467			hookType string
468			matcher  string
469			command  string
470		}{
471			{"SessionStart", "", "npx ca prime 2>/dev/null || true"},
472			{"PreCompact", "", "npx ca prime 2>/dev/null || true"},
473			{"UserPromptSubmit", "", "npx ca hooks run user-prompt 2>/dev/null || true"},
474			{"PostToolUseFailure", "Bash|Edit|Write", "npx ca hooks run post-tool-failure 2>/dev/null || true"},
475			{"PostToolUse", "Bash|Edit|Write", "npx ca hooks run post-tool-success 2>/dev/null || true"},
476			{"PostToolUse", "Read", "npx ca hooks run post-read 2>/dev/null || true"},
477			{"PreToolUse", "Edit|Write", "npx ca hooks run phase-guard 2>/dev/null || true"},
478			{"Stop", "", "npx ca hooks run phase-audit 2>/dev/null || true"},
479		}
480	
481		for _, spec := range specs {
482			entry := map[string]any{
483				"matcher": spec.matcher,
484				"hooks": []any{
485					map[string]any{
486						"type":    "command",
487						"command": spec.command,
488					},
489				},
490			}
491			arr, ok := hooks[spec.hookType].([]any)
492			if !ok {
493				arr = []any{}
494			}
495			hooks[spec.hookType] = append(arr, entry)
496		}
497	
498		settings["hooks"] = hooks
499	}
