135	// checkCmdFlags recursively checks all commands for uppercase JSON help text.
136	func checkCmdFlags(cmd *cobra.Command, violations *[]string) {
137		f := cmd.Flags().Lookup("json")
138		if f != nil {
139			usage := f.Usage
140			// Phase status uses "Output raw JSON" which is acceptable for its special case
141			if strings.HasPrefix(usage, "Output") && !strings.Contains(usage, "raw") {
142				*violations = append(*violations, cmd.CommandPath()+": "+usage)
143			}
144		}
145		for _, sub := range cmd.Commands() {
146			checkCmdFlags(sub, violations)
147		}
148	}
