501	func TestPolishCommand_InnerLoopCapturesExitCode(t *testing.T) {
502		t.Parallel()
503		root := &cobra.Command{Use: "ca"}
504		root.AddCommand(polishCmd())
505	
506		dir := t.TempDir()
507		outPath := filepath.Join(dir, "test.sh")
508	
509		_, err := executeCommand(root, "polish", "-o", outPath,
510			"--spec-file", "docs/specs/my-spec.md",
511			"--meta-epic", "test-epic-123")
512		if err != nil {
513			t.Fatalf("polish command failed: %v", err)
514		}
515	
516		data, _ := os.ReadFile(outPath)
517		script := string(data)
518	
519		// Must NOT use "|| true" which swallows exit codes
520		// The inner loop invocation must capture the exit code properly
521		innerLoopIdx := strings.Index(script, "run_inner_loop()")
522		if innerLoopIdx < 0 {
523			t.Fatal("expected run_inner_loop function")
524		}
525	
526		innerLoopFunc := script[innerLoopIdx:]
527		// Find end of function (next function definition or end of script)
528		nextFuncIdx := strings.Index(innerLoopFunc[1:], "\n}")
529		if nextFuncIdx > 0 {
530			innerLoopFunc = innerLoopFunc[:nextFuncIdx+2]
531		}
532	
533		// Must capture exit code, not swallow with || true
534		if strings.Contains(innerLoopFunc, `|| true`) {
535			t.Error("run_inner_loop must not use '|| true' on inner script invocation (swallows exit code)")
536		}
537	
538		// Must detect zero-work exit code (exit 2)
539		if !strings.Contains(innerLoopFunc, "exit 2") && !strings.Contains(innerLoopFunc, "eq 2") {
540			t.Error("run_inner_loop must detect zero-work exit code (2)")
541		}
542	}
