31	// runCmd executes a cobra command with the given args and returns stdout, stderr, and error.
32	func runCmd(cmd *cobra.Command, args []string) (stdout, stderr string, err error) {
33		var outBuf, errBuf bytes.Buffer
34		cmd.SetOut(&outBuf)
35		cmd.SetErr(&errBuf)
36		cmd.SetArgs(args)
37		err = cmd.Execute()
38		return outBuf.String(), errBuf.String(), err
39	}
