41	// buildRoot creates a root cobra command with CRUD commands registered.
42	func buildRoot() *cobra.Command {
43		root := &cobra.Command{Use: "ca", SilenceUsage: true, SilenceErrors: true}
44		registerCrudCommands(root)
45		return root
46	}
