41	func TestParseBdShowDeps(t *testing.T) {
42		tests := []struct {
43			name    string
44			input   string
45			want    []bdDep
46			wantErr bool
47		}{
48			{
49				name: "json with depends_on array",
50				input: `[{"id":"epic-1","title":"Parent","depends_on":[
51					{"id":"task-1","title":"Review: Code review","status":"closed"},
52					{"id":"task-2","title":"Compound: Synthesize patterns","status":"open"}
53				]}]`,
54				want: []bdDep{
55					{ID: "task-1", Title: "Review: Code review", Status: "closed"},
56					{ID: "task-2", Title: "Compound: Synthesize patterns", Status: "open"},
57				},
58			},
59			{
60				name: "json with dependencies array",
61				input: `{"id":"epic-1","title":"Parent","dependencies":[
62					{"id":"task-1","title":"Review: Code review","status":"closed"}
63				]}`,
64				want: []bdDep{
65					{ID: "task-1", Title: "Review: Code review", Status: "closed"},
66				},
67			},
68			{
69				name:    "empty deps",
70				input:   `[{"id":"epic-1","title":"Parent"}]`,
71				want:    []bdDep{},
72				wantErr: false,
73			},
74			{
75				name:    "invalid json",
76				input:   `not json`,
77				wantErr: true,
78			},
79			{
80				name: "depends_on takes precedence over dependencies",
81				input: `[{"id":"epic-1","depends_on":[
82					{"id":"t1","title":"Review: A","status":"closed"}
83				],"dependencies":[
84					{"id":"t2","title":"Review: B","status":"open"}
85				]}]`,
86				want: []bdDep{
87					{ID: "t1", Title: "Review: A", Status: "closed"},
88				},
89			},
90		}
91	
92		for _, tt := range tests {
93			t.Run(tt.name, func(t *testing.T) {
94				got, err := parseBdShowDeps(tt.input)
95				if (err != nil) != tt.wantErr {
96					t.Fatalf("parseBdShowDeps() error = %v, wantErr %v", err, tt.wantErr)
97				}
98				if tt.wantErr {
99					return
100				}
101				if len(got) != len(tt.want) {
102					t.Fatalf("got %d deps, want %d", len(got), len(tt.want))
103				}
104				for i, dep := range got {
105					if dep != tt.want[i] {
106						t.Errorf("dep[%d] = %+v, want %+v", i, dep, tt.want[i])
107					}
108				}
109			})
110		}
111	}
