21	func TestMain(m *testing.M) {
22		// Resolve goRoot relative to this test file's package location.
23		// This file is at go/internal/cli/, so goRoot is two levels up (go/).
24		wd, err := os.Getwd()
25		if err != nil {
26			fmt.Fprintf(os.Stderr, "getwd: %v\n", err)
27			os.Exit(1)
28		}
29		goRoot = filepath.Join(wd, "..", "..")
30		// Normalize in case of symlinks
31		goRoot, err = filepath.Abs(goRoot)
32		if err != nil {
33			fmt.Fprintf(os.Stderr, "abs: %v\n", err)
34			os.Exit(1)
35		}
36	
37		tmpDir, err := os.MkdirTemp("", "ca-e2e-*")
38		if err != nil {
39			fmt.Fprintf(os.Stderr, "mktemp: %v\n", err)
40			os.Exit(1)
41		}
42	
43		binaryPath = filepath.Join(tmpDir, "ca")
44		cmd := exec.Command("go", "build", "-o", binaryPath, "./cmd/ca")
45		cmd.Dir = goRoot
46		cmd.Stdout = os.Stderr
47		cmd.Stderr = os.Stderr
48		if err := cmd.Run(); err != nil {
49			fmt.Fprintf(os.Stderr, "build failed: %v\n", err)
50			os.RemoveAll(tmpDir)
51			os.Exit(1)
52		}
53	
54		code := m.Run()
55		os.RemoveAll(tmpDir)
56		os.Exit(code)
57	}
