93	func TestHTTPClientRejectsHTTPRedirect(t *testing.T) {
94		// Server that redirects to a plain HTTP URL
95		srv := httptest.NewTLSServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
96			http.Redirect(w, r, "http://evil.example.com/payload", http.StatusFound)
97		}))
98		defer srv.Close()
99	
100		// Use the TLS test server's client for trusted certs, but swap in our CheckRedirect
101		client := srv.Client()
102		client.CheckRedirect = httpClient.CheckRedirect
103	
104		_, err := client.Get(srv.URL + "/model")
105		if err == nil {
106			t.Fatal("expected error when redirected to HTTP, got nil")
107		}
108		// The error should mention refusing non-HTTPS
