114	func TestHTTPClientAllowsHTTPSRedirect(t *testing.T) {
115		// Final destination server
116		dest := httptest.NewTLSServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
117			w.WriteHeader(http.StatusOK)
118		}))
119		defer dest.Close()
120	
121		// Redirecting server that points to the destination (both HTTPS)
122		srv := httptest.NewTLSServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
123			http.Redirect(w, r, dest.URL+"/final", http.StatusFound)
124		}))
125		defer srv.Close()
126	
127		// We need a client that trusts both test servers' certs.
128		// Use srv's client and add our CheckRedirect. Since httptest.NewTLSServer
129		// uses the same CA in a test, this works for same-process servers.
130		client := srv.Client()
131		client.CheckRedirect = httpClient.CheckRedirect
132	
133		resp, err := client.Get(srv.URL + "/start")
134		if err != nil {
135			t.Fatalf("expected HTTPS redirect to succeed, got error: %v", err)
136		}
137		resp.Body.Close()
