16	// findRepoRoot walks up from cwd to find the repo root (contains rust/embed-daemon).
17	func findRepoRoot() string {
18		if root := os.Getenv("CA_REPO_ROOT"); root != "" {
19			return root
20		}
21		cwd, err := os.Getwd()
22		if err != nil {
23			return ""
24		}
25		dir := cwd
26		for {
27			if _, err := os.Stat(filepath.Join(dir, "rust", "embed-daemon")); err == nil {
28				return dir
29			}
30			parent := filepath.Dir(dir)
31			if parent == dir {
32				return ""
33			}
