73	// startTestDaemon starts the real Rust embed daemon for integration testing.
74	// Returns socket path, a connected client, and cleanup function.
75	func startTestDaemon(t *testing.T) (string, *Client, func()) {
76		t.Helper()
77	
78		daemonBin, modelPath, tokenizerPath := testDaemonPaths(t)
79	
80		// Use /tmp for socket to avoid path length issues on macOS
81		dir, err := os.MkdirTemp("/tmp", "embed-integ-")
82		if err != nil {
83			t.Fatalf("mkdirtemp: %v", err)
84		}
85		sockPath := filepath.Join(dir, "d.sock")
86	
87		// Start daemon with short idle timeout for test cleanup
88		cmd := exec.Command(daemonBin, sockPath, modelPath, tokenizerPath)
89		cmd.Env = append(os.Environ(), "CA_EMBED_IDLE_TIMEOUT=30")
90		cmd.Stderr = os.Stderr
91	
92		if err := cmd.Start(); err != nil {
93			os.RemoveAll(dir)
94			t.Fatalf("start daemon: %v", err)
95		}
96	
97		// Wait for daemon to become ready
98		var client *Client
99		deadline := time.Now().Add(10 * time.Second)
100		for time.Now().Before(deadline) {
101			c, err := NewClient(sockPath, 500*time.Millisecond)
102			if err != nil {
103				time.Sleep(100 * time.Millisecond)
104				continue
105			}
106			resp, err := c.Health()
107			if err != nil {
108				c.Close()
109				time.Sleep(100 * time.Millisecond)
110				continue
111			}
112			if resp.Status == "ok" {
113				client = c
114				break
115			}
116			c.Close()
117			time.Sleep(100 * time.Millisecond)
118		}
119		if client == nil {
120			cmd.Process.Kill()
121			cmd.Wait()
122			os.RemoveAll(dir)
123			t.Fatalf("daemon did not become ready within 10s")
124		}
125	
126		cleanup := func() {
127			// Send shutdown
128			client.Shutdown()
129			client.Close()
130			cmd.Wait()
131			os.RemoveAll(dir)
132		}
133	
134		return sockPath, client, cleanup
135	}
