137	func cosineSim(a, b []float64) float64 {
138		var dot, normA, normB float64
139		for i := range a {
140			dot += a[i] * b[i]
141			normA += a[i] * a[i]
142			normB += b[i] * b[i]
143		}
144		if normA == 0 || normB == 0 {
145			return 0
146		}
147		return dot / (math.Sqrt(normA) * math.Sqrt(normB))
148	}
