316	// TestIntegration_Concurrent verifies concurrent embed requests work correctly.
317	func TestIntegration_Concurrent(t *testing.T) {
318		sockPath, _, cleanup := startTestDaemon(t)
319		defer cleanup()
320	
321		var wg sync.WaitGroup
322		errs := make(chan error, 4)
323	
324		for i := 0; i < 4; i++ {
325			wg.Add(1)
326			go func(id int) {
327				defer wg.Done()
328				// Each goroutine gets its own connection
329				c, err := NewClient(sockPath, 5*time.Second)
330				if err != nil {
331					errs <- err
332					return
333				}
334				defer c.Close()
335	
336				texts := []string{"search_query: concurrent test " + string(rune('A'+id))}
337				resp, err := c.Embed(texts)
338				if err != nil {
339					errs <- err
340					return
341				}
342				if resp.IsError() {
343					errs <- &embedError{resp.Error}
344					return
345				}
346				if len(resp.Vectors) != 1 || len(resp.Vectors[0]) != 768 {
347					errs <- &embedError{"unexpected vector dimensions"}
348					return
349				}
350			}(i)
351		}
352	
353		wg.Wait()
354		close(errs)
355	
356		for err := range errs {
357			t.Errorf("concurrent request failed: %v", err)
358		}
359	}
