367	// TestIntegration_Shutdown verifies the daemon shuts down cleanly.
368	func TestIntegration_Shutdown(t *testing.T) {
369		daemonBin, modelPath, tokenizerPath := testDaemonPaths(t)
370	
371		dir, err := os.MkdirTemp("/tmp", "embed-integ-")
372		if err != nil {
373			t.Fatalf("mkdirtemp: %v", err)
374		}
375		defer os.RemoveAll(dir)
376		sockPath := filepath.Join(dir, "d.sock")
377	
378		cmd := exec.Command(daemonBin, sockPath, modelPath, tokenizerPath)
379		cmd.Env = append(os.Environ(), "CA_EMBED_IDLE_TIMEOUT=60")
380		cmd.Stderr = os.Stderr
381	
382		if err := cmd.Start(); err != nil {
383			t.Fatalf("start daemon: %v", err)
384		}
385	
386		// Wait for ready
387		var client *Client
388		deadline := time.Now().Add(10 * time.Second)
389		for time.Now().Before(deadline) {
390			c, err := NewClient(sockPath, 500*time.Millisecond)
391			if err != nil {
392				time.Sleep(100 * time.Millisecond)
393				continue
394			}
395			resp, err := c.Health()
396			if err != nil {
397				c.Close()
398				time.Sleep(100 * time.Millisecond)
399				continue
400			}
401			if resp.Status == "ok" {
402				client = c
403				break
404			}
405			c.Close()
406			time.Sleep(100 * time.Millisecond)
407		}
408		if client == nil {
409			cmd.Process.Kill()
410			cmd.Wait()
411			t.Fatalf("daemon not ready")
412		}
413	
414		// Send shutdown
415		resp, err := client.Shutdown()
416		if err != nil {
417			t.Fatalf("shutdown request: %v", err)
418		}
419		if resp.Status != "shutting_down" {
420			t.Errorf("status = %v, want shutting_down", resp.Status)
421		}
422		client.Close()
423	
424		// Wait for process to exit
425		done := make(chan error, 1)
426		go func() { done <- cmd.Wait() }()
427	
428		select {
429		case err := <-done:
430			if err != nil {
431				t.Logf("daemon exit: %v (expected for clean shutdown)", err)
432			}
433		case <-time.After(5 * time.Second):
434			cmd.Process.Kill()
435			t.Error("daemon did not exit within 5s after shutdown")
436		}
437	
438		// Socket and PID file should be cleaned up
439		time.Sleep(100 * time.Millisecond)
440		if _, err := os.Stat(sockPath); !os.IsNotExist(err) {
441			t.Error("socket file should be removed after shutdown")
442		}
443	}
