87	func writeTemp(t *testing.T, dir, name string, content []byte) string {
88		t.Helper()
89		p := filepath.Join(dir, name)
90		if err := os.WriteFile(p, content, 0o644); err != nil {
91			t.Fatal(err)
92		}
93		return p
94	}
