104		filePath := writeTemp(t, dir, "ca-binary", content)
105	
106		hash := sha256Hex(content)
107		checksumsPath := writeTemp(t, dir, "checksums.txt",
108			[]byte(hash+"  ca-binary\n"))
109	
110		ok, err := VerifyChecksum(filePath, "ca-binary", checksumsPath)
111		if err != nil {
112			t.Fatalf("unexpected error: %v", err)
113		}
114		if !ok {
