175	// packageJSON is a minimal struct for the fields we care about.
176	type packageJSON struct {
177		Version              string            `json:"version"`
178		Type                 string            `json:"type"`
179		Bin                  map[string]string `json:"bin"`
180		OS                   []string          `json:"os"`
181		CPU                  []string          `json:"cpu"`
