187	func loadPackageJSON(t *testing.T) packageJSON {
188		t.Helper()
189		// Walk up from this test file to find the repo root package.json.
190		// go/internal/npmdist -> go -> repo root
191		pkgPath := filepath.Join("..", "..", "..", "package.json")
192		data, err := os.ReadFile(pkgPath)
193		if err != nil {
194			t.Fatalf("cannot read package.json: %v", err)
195		}
196		var pkg packageJSON
197		if err := json.Unmarshal(data, &pkg); err != nil {
198			t.Fatalf("cannot parse package.json: %v", err)
199		}
200		return pkg
201	}
