127	// verifySequentialSteps checks that numbered methodology steps are in order.
128	func verifySequentialSteps(t *testing.T, review string) {
129		t.Helper()
130		methodIdx := strings.Index(review, "## Methodology")
131		if methodIdx < 0 {
132			t.Fatal("missing Methodology section")
133		}
134		rest := review[methodIdx+len("## Methodology"):]
135		if end := strings.Index(rest, "\n## "); end > 0 {
136			rest = rest[:end]
137		}
138	
139		stepRe := regexp.MustCompile(`(?m)^(\d+)\. `)
140		matches := stepRe.FindAllStringSubmatch(rest, -1)
141		if len(matches) == 0 {
142			t.Fatal("no numbered steps found")
143		}
144	
145		lastStep := 0
146		for _, m := range matches {
147			n, err := strconv.Atoi(m[1])
148			if err != nil {
149				t.Errorf("invalid step number: %s", m[1])
150				continue
151			}
152			if n <= lastStep {
153				t.Errorf("step %d not sequential (follows %d)", n, lastStep)
154			}
155			lastStep = n
156		}
157		if lastStep < 10 {
158			t.Errorf("expected >=10 methodology steps, got %d", lastStep)
159		}
160	}
