		TestCmd:  "go test ./...",
		LintCmd:  "golangci-lint run ./...",
		BuildCmd: "go build ./...",
	}
	_, updated, err := InstallPhaseSkills(dir, goStack)
	if err != nil {
		t.Fatalf("InstallPhaseSkills (go): %v", err)
	}
	if updated == 0 {
