230		// Pattern: docs/compound/research/some/path
231		refRe := regexp.MustCompile("`docs/compound/research/([^`]+)`")
232	
233		// Check all phase skills
234		for phase, content := range PhaseSkills() {
235			for _, m := range refRe.FindAllStringSubmatch(content, -1) {
236				checkResearchRef(t, "skill:"+phase, m[1], researchDocs, researchDirs)
237			}
238		}
239		for relPath, content := range PhaseSkillReferences() {
240			for _, m := range refRe.FindAllStringSubmatch(content, -1) {
241				checkResearchRef(t, "skill-ref:"+relPath, m[1], researchDocs, researchDirs)
242			}
243		}
244	
245		// Check all agent role skills
246		for role, content := range AgentRoleSkills() {
247			for _, m := range refRe.FindAllStringSubmatch(content, -1) {
248				checkResearchRef(t, "role:"+role, m[1], researchDocs, researchDirs)
249			}
250		}
251		for relPath, content := range AgentRoleSkillReferences() {
252			for _, m := range refRe.FindAllStringSubmatch(content, -1) {
253				checkResearchRef(t, "role-ref:"+relPath, m[1], researchDocs, researchDirs)
254			}
255		}
256	}
257	
258	// checkResearchRef validates a single research path reference.
259	func checkResearchRef(t *testing.T, source, ref string, docs map[string]string, dirs map[string]bool) {
260		t.Helper()
261		ref = strings.TrimSuffix(ref, "/")
262		// Could be a file or directory reference
263		if _, ok := docs[ref]; ok {
264			return // exact file match
265		}
266		if dirs[ref] {
267			return // directory reference
268		}
269		t.Errorf("%s references docs/compound/research/%s which does not exist in embedded research tree", source, ref)
270	}
