1	package setup
2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strings"
8	
9		"github.com/nathandelacretaz/dark-research-lab/internal/build"
10	)
11	
12	// InitOptions controls what init creates.
13	type InitOptions struct {
14		SkipHooks     bool
15		SkipTemplates bool   // Skip installing agent/command/skill/doc templates.
16		BinaryPath    string // Path to the Go binary for hook commands. Empty = npx fallback.
17	}
18	
19	// InitResult reports what init did.
20	type InitResult struct {
21		Success             bool
22		HooksInstalled      bool
23		HooksUpgraded       bool
24		DirsCreated         []string
25		FilesCreated        []string
26		AgentsInstalled     int
27		AgentsUpdated       int
28		CommandsInstalled   int
29		CommandsUpdated     int
30		SkillsInstalled     int
31		SkillsUpdated       int
32		RoleSkillsInstalled int
33		RoleSkillsUpdated   int
34		DocsInstalled       int
35		DocsUpdated         int
36		ResearchInstalled   int
37		ResearchUpdated     int
38		TemplatesPruned     int
39		AgentsMdUpdated     bool
40		ClaudeMdUpdated     bool
41		PluginCreated       bool
42		PluginUpdated       bool
43	}
44	
45	// initDirectories creates the .claude/ directory structure and index.jsonl.
46	func initDirectories(repoRoot string, result *InitResult) error {
47		dirs := []string{
48			filepath.Join(repoRoot, ".claude"),
49			filepath.Join(repoRoot, ".claude", "lessons"),
50			filepath.Join(repoRoot, ".claude", ".cache"),
51			filepath.Join(repoRoot, ".claude", "agents", "compound"),
52			filepath.Join(repoRoot, ".claude", "commands", "compound"),
53			filepath.Join(repoRoot, ".claude", "skills", "compound"),
54		}
55	
56		for _, dir := range dirs {
57			_, statErr := os.Stat(dir)
58			if err := os.MkdirAll(dir, 0755); err != nil {
59				return fmt.Errorf("create directory %s: %w", dir, err)
60			}
61			if os.IsNotExist(statErr) {
62				result.DirsCreated = append(result.DirsCreated, dir)
63			}
64		}
65	
66		indexPath := filepath.Join(repoRoot, ".claude", "lessons", "index.jsonl")
67		if _, err := os.Stat(indexPath); os.IsNotExist(err) {
68			if err := os.WriteFile(indexPath, []byte{}, 0644); err != nil {
69				return fmt.Errorf("create index.jsonl: %w", err)
70			}
71			result.FilesCreated = append(result.FilesCreated, indexPath)
72		}
73	
74		return EnsureGitignore(repoRoot)
75	}
76	
77	// initHooks installs or upgrades Claude Code hooks in settings.json.
78	func initHooks(repoRoot string, binaryPath string, result *InitResult) error {
79		settingsPath := filepath.Join(repoRoot, ".claude", "settings.json")
80		settings, err := ReadClaudeSettings(settingsPath)
81		if err != nil {
82			return fmt.Errorf("read settings: %w", err)
83		}
84	
85		needsInstall := !HasAllHooks(settings)
86		needsUpgrade := HooksNeedUpgrade(settings, binaryPath)
87		needsDedupe := HooksNeedDedupe(settings)
88	
89		if needsInstall || needsUpgrade || needsDedupe {
90			AddAllHooks(settings, binaryPath)
91			if err := WriteClaudeSettings(settingsPath, settings); err != nil {
92				return fmt.Errorf("write settings: %w", err)
93			}
94			result.HooksUpgraded = needsUpgrade && !needsInstall
95		}
96		result.HooksInstalled = true
97		return nil
98	}
99	
100	// installTemplates installs all template assets (agents, commands, skills, docs).
101	// Detects the project stack to substitute quality gate placeholders.
102	func installTemplates(repoRoot string, result *InitResult) error {
103		version := build.Version
104	
105		updated, err := UpdateAgentsMd(repoRoot)
106		if err != nil {
107			return fmt.Errorf("update AGENTS.md: %w", err)
108		}
109		result.AgentsMdUpdated = updated
110	
111		updated, err = EnsureClaudeMdReference(repoRoot)
112		if err != nil {
113			return fmt.Errorf("ensure CLAUDE.md reference: %w", err)
114		}
115		result.ClaudeMdUpdated = updated
116	
117		created, pluginUpdated, err := CreatePluginManifest(repoRoot, version)
118		if err != nil {
119			return fmt.Errorf("create plugin.json: %w", err)
120		}
121		result.PluginCreated = created
122		result.PluginUpdated = pluginUpdated
123	
124		stack := DetectStack(repoRoot)
125		return installTemplateGroups(repoRoot, version, stack, result)
126	}
127	
128	// installTemplateGroups installs agent, command, skill, role skill, and doc templates.
129	// Stack info is used to substitute quality gate placeholders in skills and docs.
130	func installTemplateGroups(repoRoot string, version string, stack StackInfo, result *InitResult) error {
131		type installFunc struct {
132			fn   func() (int, int, error)
133			setN func(int)
134			setU func(int)
135			name string
136		}
137		groups := []installFunc{
138			{func() (int, int, error) { return InstallAgentTemplates(repoRoot) },
139				func(n int) { result.AgentsInstalled = n }, func(u int) { result.AgentsUpdated = u }, "agent templates"},
140			{func() (int, int, error) { return InstallWorkflowCommands(repoRoot) },
141				func(n int) { result.CommandsInstalled = n }, func(u int) { result.CommandsUpdated = u }, "workflow commands"},
142			{func() (int, int, error) { return InstallPhaseSkills(repoRoot, stack) },
143				func(n int) { result.SkillsInstalled = n }, func(u int) { result.SkillsUpdated = u }, "phase skills"},
144			{func() (int, int, error) { return InstallAgentRoleSkills(repoRoot) },
145				func(n int) { result.RoleSkillsInstalled = n }, func(u int) { result.RoleSkillsUpdated = u }, "agent role skills"},
146			{func() (int, int, error) { return InstallDocTemplates(repoRoot, version, stack) },
147				func(n int) { result.DocsInstalled = n }, func(u int) { result.DocsUpdated = u }, "doc templates"},
148			{func() (int, int, error) { return InstallResearchDocs(repoRoot) },
149				func(n int) { result.ResearchInstalled = n }, func(u int) { result.ResearchUpdated = u }, "research docs"},
150		}
151	
152		for _, g := range groups {
153			n, u, err := g.fn()
154			if err != nil {
155				return fmt.Errorf("install %s: %w", g.name, err)
156			}
157			g.setN(n)
158			g.setU(u)
159		}
160	
161		pruned, err := PruneStaleTemplates(repoRoot)
162		if err != nil {
163			return fmt.Errorf("prune stale templates: %w", err)
164		}
165		result.TemplatesPruned = pruned
166	
167		if err := CompileSkillsIndex(repoRoot); err != nil {
168			return fmt.Errorf("compile skills index: %w", err)
169		}
170		return nil
171	}
172	
173	// InitRepo initializes dark-research-lab in a repository.
174	// Creates .claude/ structure, lessons index, and optionally installs hooks.
175	func InitRepo(repoRoot string, opts InitOptions) (*InitResult, error) {
176		result := &InitResult{Success: true}
177	
178		if err := initDirectories(repoRoot, result); err != nil {
179			return nil, err
180		}
181	
182		if !opts.SkipHooks {
183			if err := initHooks(repoRoot, opts.BinaryPath, result); err != nil {
184				return nil, err
185			}
186		}
187	
188		if !opts.SkipTemplates {
189			if err := installTemplates(repoRoot, result); err != nil {
190				return nil, err
191			}
192		}
193	
194		return result, nil
195	}
196	
197	// EnsureGitignore creates or updates .claude/.gitignore with required patterns.
198	func EnsureGitignore(repoRoot string) error {
199		gitignorePath := filepath.Join(repoRoot, ".claude", ".gitignore")
200	
201		// Ensure directory exists
202		if err := os.MkdirAll(filepath.Dir(gitignorePath), 0755); err != nil {
203			return err
204		}
205	
206		marker := "# drl managed"
207		patterns := marker + `
208	.cache/
209	*.sqlite
210	*.sqlite-shm
211	*.sqlite-wal
212	.drl-phase-state.json
213	.drl-failure-state.json
214	.drl-read-state.json
215	.drl-hints-shown
216	skills/compound/skills_index.json
217	`
218	
219		// If gitignore exists, check for our marker
220		existing, err := os.ReadFile(gitignorePath)
221		if err == nil {
222			if strings.Contains(string(existing), marker) {
223				return nil // Already has our patterns
224			}
225			// Append our patterns to existing content
226			combined := strings.TrimRight(string(existing), "\n") + "\n" + patterns
227			return os.WriteFile(gitignorePath, []byte(combined), 0644)
228		}
229		if !os.IsNotExist(err) {
230			return fmt.Errorf("read .gitignore: %w", err)
231		}
232	
233		return os.WriteFile(gitignorePath, []byte(patterns), 0644)
234	}
