228			Short: "Install Claude Code hooks",
229			RunE:  func(cmd *cobra.Command, args []string) error { return runSetupClaude(cmd, opts) },
230		}
231	
232		cmd.Flags().BoolVar(&opts.uninstall, "uninstall", false, "Remove dark-research-lab hooks")
233		cmd.Flags().BoolVar(&opts.status, "status", false, "Check integration status")
234		cmd.Flags().BoolVar(&opts.global, "global", false, "Use global ~/.claude/ settings")
235		cmd.Flags().BoolVar(&opts.dryRun, "dry-run", false, "Show what would change without writing")
236		cmd.Flags().BoolVar(&opts.jsonOut, "json", false, "output as JSON")
237		cmd.Flags().StringVar(&opts.repoRoot, "repo-root", "", "Repository root")
238	
239		parent.AddCommand(cmd)
