275	// hookAction classifies the action to take based on hook state.
276	// Returns a present-tense verb ("install", "upgrade", "reconcile", "unchanged").
277	func hookAction(installed, needsUpgrade, needsDedupe bool) string {
278		if installed && !needsUpgrade && !needsDedupe {
279			return "unchanged"
280		}
281		if needsUpgrade && needsDedupe {
282			return "reconcile"
283		}
284		if needsUpgrade {
285			return "upgrade"
286		}
287		if needsDedupe {
288			return "reconcile"
289		}
290		return "install"
291	}
