487	func doctorCmd() *cobra.Command {
488		var (
489			repoRoot string
490			jsonOut  bool
491		)
492		cmd := &cobra.Command{
493			Use:   "doctor",
494			Short: "Check dark-research-lab health",
495			RunE: func(cmd *cobra.Command, args []string) error {
496				if repoRoot == "" {
497					repoRoot = util.GetRepoRoot()
498				}
499				checks := runDoctorChecks(repoRoot)
500				if jsonOut {
501					return writeJSON(cmd, map[string]any{"checks": checks})
502				}
503				printDoctorResults(cmd, checks)
504				return nil
505			},
506		}
507		cmd.Flags().StringVar(&repoRoot, "repo-root", "", "Repository root")
508		cmd.Flags().BoolVar(&jsonOut, "json", false, "output as JSON")
509		return cmd
510	}
