512	func runDoctorChecks(repoRoot string) []doctorCheck {
513		var checks []doctorCheck
514	
515		// 1. .claude/ directory exists
516		claudeDir := filepath.Join(repoRoot, ".claude")
517		if _, err := os.Stat(claudeDir); err == nil {
518			checks = append(checks, doctorCheck{Name: ".claude/ directory exists", Status: "pass"})
519		} else {
520			checks = append(checks, doctorCheck{Name: ".claude/ directory exists", Status: "fail", Fix: "Run: drl init"})
521		}
522	
523		// 2. Lessons index exists
524		indexPath := filepath.Join(repoRoot, ".claude", "lessons", "index.jsonl")
525		if _, err := os.Stat(indexPath); err == nil {
526			checks = append(checks, doctorCheck{Name: "Lessons index present", Status: "pass"})
527		} else {
528			checks = append(checks, doctorCheck{Name: "Lessons index present", Status: "fail", Fix: "Run: drl init"})
529		}
530	
531		// 3. Claude hooks configured
532		checks = append(checks, checkHooks(repoRoot))
533	
534		// 4. .gitignore health
535		gitignorePath := filepath.Join(repoRoot, ".claude", ".gitignore")
536		if _, err := os.Stat(gitignorePath); err == nil {
537			checks = append(checks, doctorCheck{Name: ".claude/.gitignore present", Status: "pass"})
538		} else {
539			checks = append(checks, doctorCheck{Name: ".claude/.gitignore present", Status: "warn", Fix: "Run: drl init"})
540		}
541	
542		// 5. Go binary healthy (always pass since we're running)
543		checks = append(checks, doctorCheck{Name: "Go binary healthy", Status: "pass"})
544	
545		// 6. Beads CLI available
546		if _, err := os.Stat(filepath.Join(repoRoot, ".beads")); err == nil {
547			checks = append(checks, doctorCheck{Name: "Beads initialized", Status: "pass"})
548		} else {
549			checks = append(checks, doctorCheck{Name: "Beads initialized", Status: "warn", Fix: "Run: bd init"})
550		}
551	
552		// 7. Windows platform notice (under WSL2, GOOS is "linux")
553		if runtime.GOOS == "windows" {
554			checks = append(checks, doctorCheck{
555				Name:   "Windows platform",
556				Status: "info",
557				Fix:    "Vector search requires embed daemon (Unix only); keyword search works natively.",
558			})
559		}
560	
561		return checks
562	}
563	
564	// checkHooks verifies Claude Code hooks are installed and healthy.
565	func checkHooks(repoRoot string) doctorCheck {
566		settingsPath := filepath.Join(repoRoot, ".claude", "settings.json")
567		settings, err := setup.ReadClaudeSettings(settingsPath)
568		if err != nil || !setup.HasAllHooks(settings) {
569			return doctorCheck{Name: "Claude Code hooks installed", Status: "warn", Fix: "Run: drl setup claude"}
570		}
571		binaryPath := resolveBinaryPath()
572		if setup.HooksNeedUpgrade(settings, binaryPath) {
573			return doctorCheck{Name: "Claude Code hooks installed", Status: "warn", Fix: "Hooks are stale (npx). Run: drl setup claude"}
574		}
575		if setup.HooksNeedDedupe(settings) {
576			return doctorCheck{Name: "Claude Code hooks installed", Status: "warn", Fix: "Hooks are duplicated. Run: drl setup claude"}
577		}
578		return doctorCheck{Name: "Claude Code hooks installed", Status: "pass"}
579	}
