19	// SkillEntry represents a single skill in the compiled index.
20	type SkillEntry struct {
21		Name        string `json:"name"`
22		Description string `json:"description"`
23		Phase       string `json:"phase,omitempty"`
24		Dir         string `json:"dir"`
25	}
26	
27	// SkillsIndex is the top-level structure of skills_index.json.
28	type SkillsIndex struct {
29		Skills []SkillEntry `json:"skills"`
30	}
31	
32	// extractFrontmatter extracts YAML frontmatter fields from SKILL.md content.
33	func extractFrontmatter(content string) (name, description, phase string) {
34		lines := strings.Split(content, "\n")
35		inFrontmatter := false
36		for _, line := range lines {
37			trimmed := strings.TrimSpace(line)
38			if trimmed == "---" {
39				if inFrontmatter {
40					break
41				}
42				inFrontmatter = true
43				continue
44			}
45			if !inFrontmatter {
46				continue
47			}
48			if strings.HasPrefix(trimmed, "name:") {
49				name = stripYAMLQuotes(strings.TrimSpace(strings.TrimPrefix(trimmed, "name:")))
50			} else if strings.HasPrefix(trimmed, "description:") {
51				description = stripYAMLQuotes(strings.TrimSpace(strings.TrimPrefix(trimmed, "description:")))
52			} else if strings.HasPrefix(trimmed, "phase:") {
53				phase = stripYAMLQuotes(strings.TrimSpace(strings.TrimPrefix(trimmed, "phase:")))
54			}
55		}
56		return
57	}
58	
59	// stripYAMLQuotes removes surrounding single or double quotes from a YAML value.
60	func stripYAMLQuotes(s string) string {
61		if len(s) >= 2 && ((s[0] == '"' && s[len(s)-1] == '"') || (s[0] == '\'' && s[len(s)-1] == '\'')) {
62			return s[1 : len(s)-1]
63		}
64		return s
65	}
66	
67	// CompileSkillsIndex pre-compiles a skills_index.json from embedded SKILL.md
68	// frontmatter. Written to .claude/skills/compound/skills_index.json during setup.
69	func CompileSkillsIndex(repoRoot string) error {
70		skills := templates.PhaseSkills()
71		var entries []SkillEntry
72		for dir, content := range skills {
73			name, description, phase := extractFrontmatter(content)
74			entries = append(entries, SkillEntry{
75				Name:        name,
76				Description: description,
77				Phase:       phase,
78				Dir:         dir,
79			})
80		}
81	
82		sort.Slice(entries, func(i, j int) bool {
83			return entries[i].Dir < entries[j].Dir
84		})
85	
86		index := SkillsIndex{Skills: entries}
87		data, err := json.MarshalIndent(index, "", "  ")
88		if err != nil {
89			return fmt.Errorf("marshal skills index: %w", err)
90		}
91	
92		indexPath := filepath.Join(repoRoot, ".claude", "skills", "compound", "skills_index.json")
93		if err := os.MkdirAll(filepath.Dir(indexPath), 0755); err != nil {
94			return fmt.Errorf("mkdir for skills index: %w", err)
95		}
96		return os.WriteFile(indexPath, data, 0644)
97	}
