108	// reconcileFile creates or updates a file at filePath with content.
109	// Returns (created, updated) booleans. Updates only when content differs.
110	func reconcileFile(filePath string, content string) (bool, bool, error) {
111		existing, err := os.ReadFile(filePath)
112		if errors.Is(err, os.ErrNotExist) {
113			if wErr := os.WriteFile(filePath, []byte(content), 0644); wErr != nil {
114				return false, false, fmt.Errorf("write %s: %w", filePath, wErr)
115			}
116			return true, false, nil
117		}
118		if err != nil {
119			return false, false, fmt.Errorf("read %s: %w", filePath, err)
120		}
121		if string(existing) != content {
122			if wErr := os.WriteFile(filePath, []byte(content), 0644); wErr != nil {
123				return false, false, fmt.Errorf("write %s: %w", filePath, wErr)
124			}
125			return false, true, nil
126		}
127		return false, false, nil
128	}
