153	// substituteQualityGates replaces quality gate placeholders in content with the
154	// detected stack commands.
155	func substituteQualityGates(content string, stack StackInfo) string {
156		stack = stack.withFallbacks()
157		content = strings.ReplaceAll(content, "{{QUALITY_GATE_TEST}}", stack.TestCmd)
158		content = strings.ReplaceAll(content, "{{QUALITY_GATE_LINT}}", stack.LintCmd)
159		content = strings.ReplaceAll(content, "{{QUALITY_GATE_BUILD}}", stack.BuildCmd)
160		return content
