175			}
176			if c {
177				created++
178			}
179			if u {
180				updated++
181			}
182		}
183	
184		for relPath, content := range templates.PhaseSkillReferences() {
185			content = substituteQualityGates(content, stack)
186			filePath := filepath.Join(repoRoot, ".claude", "skills", "compound", relPath)
187			c, u, err := writeSkillFile(filePath, content)
188			if err != nil {
189				return created, updated, err
190			}
191			if c {
192				created++
193			}
194			if u {
195				updated++
196			}
197		}
