544	// pruneStaleFiles removes files from dir that are not in the expected map (by filename key).
545	// Skips subdirectories. Returns count of files removed.
546	func pruneStaleFiles(dir string, expected map[string]string) (int, error) {
547		entries, err := os.ReadDir(dir)
548		if err != nil {
549			if errors.Is(err, os.ErrNotExist) {
550				return 0, nil
551			}
552			return 0, fmt.Errorf("read %s: %w", dir, err)
553		}
554		pruned := 0
555		for _, entry := range entries {
556			if entry.IsDir() {
557				continue
558			}
559			if _, ok := expected[entry.Name()]; !ok {
560				if rErr := os.Remove(filepath.Join(dir, entry.Name())); rErr != nil {
561					return pruned, fmt.Errorf("remove %s: %w", entry.Name(), rErr)
562				}
563				pruned++
564			}
565		}
566		return pruned, nil
567	}
