569	// shouldSkipEntry returns true if the entry should be preserved without pruning.
570	func shouldSkipEntry(entry os.DirEntry, relDir string, relPath string, skipTopLevel map[string]bool) bool {
571		return entry.IsDir() && relDir == "" && skipTopLevel[entry.Name()]
572	}
