574	// pruneDir handles pruning of a directory entry. Returns (pruned count, error).
575	func pruneDir(root, relPath string, expectedDirs map[string]bool, expectedFiles map[string]bool, skipTopLevel map[string]bool) (int, error) {
576		if !expectedDirs[relPath] {
577			if err := os.RemoveAll(filepath.Join(root, filepath.FromSlash(relPath))); err != nil {
578				return 0, fmt.Errorf("remove %s: %w", relPath, err)
579			}
580			return 1, nil
581		}
582		return pruneManagedSubtree(root, relPath, expectedFiles, expectedDirs, skipTopLevel)
583	}
