199	// runSetupClaude executes the setup claude command logic.
200	func runSetupClaude(cmd *cobra.Command, opts *setupClaudeOpts) error {
201		if opts.repoRoot == "" {
202			opts.repoRoot = util.GetRepoRoot()
203		}
204	
205		settingsPath := filepath.Join(opts.repoRoot, ".claude", "settings.json")
206		displayPath := ".claude/settings.json"
207		if opts.global {
208			home, _ := os.UserHomeDir()
209			settingsPath = filepath.Join(home, ".claude", "settings.json")
210			displayPath = "~/.claude/settings.json"
211		}
212	
213		settings, err := setup.ReadClaudeSettings(settingsPath)
214		if err != nil {
215			return fmt.Errorf("read settings: %w", err)
216		}
217	
218		installed := setup.HasAllHooks(settings)
219		binaryPath := resolveBinaryPath()
220		needsUpgrade := setup.HooksNeedUpgrade(settings, binaryPath)
221		needsDedupe := setup.HooksNeedDedupe(settings)
222	
223		if opts.status {
224			return handleClaudeStatus(cmd, installed, needsUpgrade, needsDedupe, displayPath, settingsPath, opts.jsonOut)
225		}
226		if opts.uninstall {
227			return handleClaudeUninstall(cmd, settings, settingsPath, installed, displayPath, opts.jsonOut)
228		}
229		if opts.dryRun {
230			return handleClaudeDryRun(cmd, installed, needsUpgrade, needsDedupe, displayPath, opts.jsonOut)
231		}
232		return handleClaudeInstall(cmd, settings, settingsPath, installed, needsUpgrade, needsDedupe, binaryPath, displayPath, opts.jsonOut)
233	}
