287	// hookAction classifies the action to take based on hook state.
288	// Returns a present-tense verb ("install", "upgrade", "reconcile", "unchanged").
289	func hookAction(installed, needsUpgrade, needsDedupe bool) string {
290		if installed && !needsUpgrade && !needsDedupe {
291			return "unchanged"
292		}
293		if needsUpgrade && needsDedupe {
294			return "reconcile"
295		}
296		if needsUpgrade {
297			return "upgrade"
298		}
299		if needsDedupe {
300			return "reconcile"
301		}
302		return "install"
303	}
304	
305	// hookActionPastTense maps present-tense actions to past-tense for output messages.
306	var hookActionPastTense = map[string]string{
307		"install":   "installed",
308		"upgrade":   "upgraded",
309		"reconcile": "reconciled",
310		"unchanged": "unchanged",
311	}
