313	func handleClaudeDryRun(cmd *cobra.Command, installed bool, needsUpgrade bool, needsDedupe bool, displayPath string, jsonOut bool) error {
314		action := hookAction(installed, needsUpgrade, needsDedupe)
315	
316		if jsonOut {
317			return writeJSON(cmd, map[string]any{
318				"dryRun":       true,
319				"location":     displayPath,
320				"action":       action,
321				"installed":    installed,
322				"needsUpgrade": needsUpgrade,
323				"needsDedupe":  needsDedupe,
324			})
325		}
326	
327		cmd.Println("[dry-run] Claude Code hooks analysis:")
328		cmd.Printf("  Settings file: %s\n", displayPath)
329		cmd.Printf("  Currently installed: %v\n", installed)
330		if action == "unchanged" {
331			cmd.Println("  Action: no changes needed")
332		} else {
333			cmd.Printf("  Action would: %s\n", action)
334		}
335		if needsUpgrade {
336			cmd.Println("  Upgrade: npx hooks would be upgraded to binary path")
337		}
338		if needsDedupe {
339			cmd.Println("  Deduplicate: duplicate hook entries would be removed")
340		}
341		return nil
342	}
