344	func handleClaudeInstall(cmd *cobra.Command, settings map[string]any, settingsPath string, installed bool, needsUpgrade bool, needsDedupe bool, binaryPath string, displayPath string, jsonOut bool) error {
345		if installed && !needsUpgrade && !needsDedupe {
346			return printClaudeResult(cmd, displayPath, "unchanged", jsonOut)
347		}
348	
349		setup.AddAllHooks(settings, binaryPath)
350		if err := setup.WriteClaudeSettings(settingsPath, settings); err != nil {
351			return fmt.Errorf("write settings: %w", err)
352		}
353	
354		action := hookActionPastTense[hookAction(installed, needsUpgrade, needsDedupe)]
355		return printClaudeResult(cmd, displayPath, action, jsonOut)
356	}
