360			return writeJSON(cmd, map[string]any{
361				"installed": true,
362				"location":  displayPath,
363				"action":    action,
364			})
365		}
366	
367		messages := map[string]string{
368			"unchanged":  fmt.Sprintf("[info] Compound agent hooks already installed at %s", displayPath),
369			"installed":  fmt.Sprintf("[ok] Claude Code hooks installed to %s", displayPath),
370			"upgraded":   fmt.Sprintf("[ok] Claude Code hooks upgraded in %s (npx → binary)", displayPath),
371			"reconciled": fmt.Sprintf("[ok] Claude Code hooks reconciled in %s (upgraded + deduplicated)", displayPath),
372		}
373		if msg, ok := messages[action]; ok {
