462	// printDoctorResults renders doctor check results to the command output.
463	func printDoctorResults(cmd *cobra.Command, checks []doctorCheck) {
464		passCount, failCount, warnCount, infoCount := 0, 0, 0, 0
465		for _, c := range checks {
466			icon := "[ok]"
467			switch c.Status {
468			case "fail":
469				icon = "[fail]"
470				failCount++
471			case "warn":
472				icon = "[warn]"
473				warnCount++
474			case "info":
475				icon = "[info]"
476				infoCount++
477			default:
478				passCount++
479			}
480			cmd.Printf("  %s %s\n", icon, c.Name)
481			if c.Fix != "" {
482				cmd.Printf("       Fix: %s\n", c.Fix)
483			}
484		}
485		cmd.Println()
486		if infoCount > 0 {
487			cmd.Printf("Results: %d passed, %d failed, %d warnings, %d info\n", passCount, failCount, warnCount, infoCount)
488		} else {
489			cmd.Printf("Results: %d passed, %d failed, %d warnings\n", passCount, failCount, warnCount)
490		}
491	}
492	
493	type doctorCheck struct {
494		Name   string `json:"name"`
495		Status string `json:"status"` // "pass", "fail", "warn", "info"
496		Fix    string `json:"fix,omitempty"`
497	}
498	
499	func doctorCmd() *cobra.Command {
500		var (
501			repoRoot string
502			jsonOut  bool
503		)
504		cmd := &cobra.Command{
505			Use:   "doctor",
506			Short: "Check dark-research-lab health",
507			RunE: func(cmd *cobra.Command, args []string) error {
508				if repoRoot == "" {
509					repoRoot = util.GetRepoRoot()
510				}
511				checks := runDoctorChecks(repoRoot)
512				if jsonOut {
513					return writeJSON(cmd, map[string]any{"checks": checks})
514				}
515				printDoctorResults(cmd, checks)
516				return nil
517			},
518		}
519		cmd.Flags().StringVar(&repoRoot, "repo-root", "", "Repository root")
520		cmd.Flags().BoolVar(&jsonOut, "json", false, "output as JSON")
521		return cmd
522	}
523	
524	func runDoctorChecks(repoRoot string) []doctorCheck {
525		var checks []doctorCheck
526	
527		// 1. .claude/ directory exists
528		claudeDir := filepath.Join(repoRoot, ".claude")
529		if _, err := os.Stat(claudeDir); err == nil {
530			checks = append(checks, doctorCheck{Name: ".claude/ directory exists", Status: "pass"})
531		} else {
532			checks = append(checks, doctorCheck{Name: ".claude/ directory exists", Status: "fail", Fix: "Run: drl init"})
533		}
534	
535		// 2. Lessons index exists
536		indexPath := filepath.Join(repoRoot, ".claude", "lessons", "index.jsonl")
537		if _, err := os.Stat(indexPath); err == nil {
538			checks = append(checks, doctorCheck{Name: "Lessons index present", Status: "pass"})
539		} else {
540			checks = append(checks, doctorCheck{Name: "Lessons index present", Status: "fail", Fix: "Run: drl init"})
541		}
542	
543		// 3. Claude hooks configured
544		checks = append(checks, checkHooks(repoRoot))
545	
546		// 4. .gitignore health
547		gitignorePath := filepath.Join(repoRoot, ".claude", ".gitignore")
548		if _, err := os.Stat(gitignorePath); err == nil {
549			checks = append(checks, doctorCheck{Name: ".claude/.gitignore present", Status: "pass"})
550		} else {
551			checks = append(checks, doctorCheck{Name: ".claude/.gitignore present", Status: "warn", Fix: "Run: drl init"})
552		}
553	
554		// 5. Go binary healthy (always pass since we're running)
555		checks = append(checks, doctorCheck{Name: "Go binary healthy", Status: "pass"})
556	
557		// 6. Beads CLI available
558		if _, err := os.Stat(filepath.Join(repoRoot, ".beads")); err == nil {
559			checks = append(checks, doctorCheck{Name: "Beads initialized", Status: "pass"})
560		} else {
561			checks = append(checks, doctorCheck{Name: "Beads initialized", Status: "warn", Fix: "Run: bd init"})
562		}
563	
564		// 7. Windows platform notice (under WSL2, GOOS is "linux")
565		if runtime.GOOS == "windows" {
566			checks = append(checks, doctorCheck{
567				Name:   "Windows platform",
568				Status: "info",
569				Fix:    "Vector search requires embed daemon (Unix only); keyword search works natively.",
570			})
571		}
572	
573		return checks
574	}
575	
576	// checkHooks verifies Claude Code hooks are installed and healthy.
577	func checkHooks(repoRoot string) doctorCheck {
578		settingsPath := filepath.Join(repoRoot, ".claude", "settings.json")
579		settings, err := setup.ReadClaudeSettings(settingsPath)
580		if err != nil || !setup.HasAllHooks(settings) {
581			return doctorCheck{Name: "Claude Code hooks installed", Status: "warn", Fix: "Run: drl setup claude"}
582		}
583		binaryPath := resolveBinaryPath()
584		if setup.HooksNeedUpgrade(settings, binaryPath) {
585			return doctorCheck{Name: "Claude Code hooks installed", Status: "warn", Fix: "Hooks are stale (npx). Run: drl setup claude"}
586		}
587		if setup.HooksNeedDedupe(settings) {
588			return doctorCheck{Name: "Claude Code hooks installed", Status: "warn", Fix: "Hooks are duplicated. Run: drl setup claude"}
589		}
590		return doctorCheck{Name: "Claude Code hooks installed", Status: "pass"}
591	}
