593	// printBeadsStatus reports beads CLI and repo initialization status.
594	func printBeadsStatus(cmd *cobra.Command, repoRoot string) {
595		// Check if bd CLI is in PATH
596		bdInstalled := false
597		for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
598			if _, err := os.Stat(filepath.Join(dir, "bd")); err == nil {
599				bdInstalled = true
600				break
601			}
602		}
603	
604		if !bdInstalled {
605			cmd.Println("  Beads: not installed")
606			cmd.Println("         Install: curl -sSL https://raw.githubusercontent.com/steveyegge/beads/main/scripts/install.sh | bash")
607			return
608		}
609	
610		// Check if .beads/ is initialized in this repo
611		if _, err := os.Stat(filepath.Join(repoRoot, ".beads")); err == nil {
612			cmd.Println("  Beads: initialized")
613		} else {
614			cmd.Println("  Beads: installed but not initialized in this repo")
615			cmd.Println("         Run: bd init")
616		}
617	}
