106	// executeSearch performs hybrid or keyword-only search depending on embedder availability.
107	func executeSearch(db *sql.DB, embedder search.Embedder, query string, limit int, repoRoot string) ([]memory.Item, error) {
108		if embedder != nil {
109			return executeHybridSearch(db, embedder, query, limit, repoRoot)
110		}
111		if runtime.GOOS == "windows" {
112			emitWindowsSearchNotice(repoRoot)
113		}
114		sdb := storage.NewSearchDB(db)
115		items, err := sdb.SearchKeyword(query, limit, "")
116		if err != nil {
117			return nil, fmt.Errorf("keyword search: %w", err)
118		}
119		return items, nil
120	}
