122	// executeHybridSearch runs vector + keyword search and merges results.
123	func executeHybridSearch(db *sql.DB, embedder search.Embedder, query string, limit int, repoRoot string) ([]memory.Item, error) {
124		candidateLimit := limit * search.CandidateMultiplier
125	
126		vecResults, vecErr := search.Vector(db, embedder, query, candidateLimit, repoRoot)
127	
128		sdb := storage.NewSearchDB(db)
129		kwScored, kwErr := sdb.SearchKeywordScored(query, candidateLimit, "")
130		if kwErr != nil {
131			return nil, fmt.Errorf("keyword search: %w", kwErr)
132		}
133	
134		kwItems := make([]search.ScoredItem, len(kwScored))
135		for i, r := range kwScored {
136			kwItems[i] = search.ScoredItem{Item: r.Item, Score: r.Score}
137		}
138	
139		var merged []search.ScoredItem
140		if vecErr != nil {
141			merged = kwItems
142		} else {
143			merged = search.MergeHybridScores(vecResults, kwItems, &search.HybridMergeOptions{
144				MinScore: search.MinHybridScore,
145			})
146		}
147	
148		ranked := search.RankItems(merged)
149		if len(ranked) > limit {
150			ranked = ranked[:limit]
151		}
152	
153		items := make([]memory.Item, len(ranked))
154		for i, r := range ranked {
155			items[i] = r.Item
156		}
157		return items, nil
158	}
