269	// resolvePlanText returns the plan text from the flag or stdin.
270	func resolvePlanText(planText string) (string, error) {
271		if planText == "" {
272			fi, _ := os.Stdin.Stat()
273			if fi != nil && (fi.Mode()&os.ModeCharDevice) == 0 {
274				text, err := util.ReadStdinFrom(os.Stdin, 5*time.Second, 1024*1024)
275				if err != nil {
276					return "", fmt.Errorf("read stdin: %w", err)
277				}
278				planText = strings.TrimSpace(text)
279			}
280		}
281		if planText == "" {
282			return "", fmt.Errorf("no plan provided; use --plan <text> or pipe text to stdin")
283		}
284		return planText, nil
285	}
