323	type embedderAdapter struct {
324		client *embed.Client
325	}
326	
327	func (a *embedderAdapter) Embed(texts []string) ([][]float64, error) {
328		resp, err := a.client.Embed(texts)
329		if err != nil {
330			return nil, err
331		}
332		if resp.IsError() {
333			return nil, fmt.Errorf("daemon error: %s", resp.Error)
334		}
335		return resp.Vectors, nil
336	}
