397	func formatSearchResults(items []memory.Item) string {
398		if len(items) == 0 {
399			return "No lessons match your search. Try a different query or use \"list\" to see all lessons.\n"
400		}
401	
402		var b strings.Builder
403		fmt.Fprintf(&b, "[info] Found %d lesson(s):\n", len(items))
404	
405		for _, item := range items {
406			fmt.Fprintf(&b, "\n[%s] %s\n", item.ID, item.Insight)
407			fmt.Fprintf(&b, "  Trigger: %s\n", item.Trigger)
408			if len(item.Tags) > 0 {
409				fmt.Fprintf(&b, "  Tags: %s\n", strings.Join(item.Tags, ", "))
410			}
411		}
412		return b.String()
413	}
