415	func formatListResults(items []memory.Item, total int, skippedCount int) string {
416		var b strings.Builder
417	
418		if len(items) == 0 {
419			b.WriteString("No lessons found. Get started with: learn \"Your first lesson\"\n")
420		} else {
421			fmt.Fprintf(&b, "[info] Showing %d of %d item(s):\n", len(items), total)
422			for _, item := range items {
423				fmt.Fprintf(&b, "\n[%s] %s\n", item.ID, item.Insight)
424				fmt.Fprintf(&b, "  Type: %s | Source: %s\n", item.Type, formatSource(item.Source))
425				if len(item.Tags) > 0 {
426					fmt.Fprintf(&b, "  Tags: %s\n", strings.Join(item.Tags, ", "))
427				}
428			}
429		}
430	
431		if skippedCount > 0 {
432			fmt.Fprintf(&b, "\n[warn] %d corrupted lesson(s) skipped.\n", skippedCount)
433		}
434		return b.String()
435	}
