437	func formatSessionHuman(items []memory.Item, totalCount int) string {
438		if len(items) == 0 {
439			return "No high-severity lessons found. Run `drl learn \"<insight>\"` to capture your first lesson.\n"
440		}
441	
442		var b strings.Builder
443		b.WriteString("## Lessons from Past Sessions\n\n")
444		b.WriteString("These lessons were captured from previous corrections and should inform your work:\n\n")
445	
446		for i, item := range items {
447			tags := ""
448			if len(item.Tags) > 0 {
449				tags = " (" + strings.Join(item.Tags, ", ") + ")"
450			}
451			fmt.Fprintf(&b, "%d. **%s**%s\n", i+1, item.Insight, tags)
452			fmt.Fprintf(&b, "   Learned: %s via %s\n\n", datePrefix(item.Created), formatSource(item.Source))
453		}
454	
455		if totalCount > LessonCountWarning {
456			fmt.Fprintf(&b, "[info] %d lessons in index. Consider `drl compact` to reduce context pollution.\n", totalCount)
457		}
458	
459		oldCount := countOldLessons(items)
460		if oldCount > 0 {
461			fmt.Fprintf(&b, "[warn] %d lesson(s) are over 90 days old. Review for continued validity.\n", oldCount)
462		}
463	
464		return b.String()
465	}
