523			Count   int          `json:"count"`
524		}{
525			Lessons: lessons,
526			Count:   len(lessons),
527		}
528		out, err := json.Marshal(data)
529		if err != nil {
530			return "", fmt.Errorf("marshal check-plan JSON: %w", err)
531		}
532		return string(out), nil
