534	
535	func countOldLessons(items []memory.Item) int {
536		threshold := time.Now().AddDate(0, 0, -AgeFlagThresholdDays)
537		count := 0
538		for _, item := range items {
539			created, err := time.Parse(time.RFC3339, item.Created)
540			if err != nil {
541				continue
542			}
543			if created.Before(threshold) {
544				count++
545			}
546		}
547		return count
548	}
