76	func openURL(rawURL string) {
77		// Validate URL scheme to prevent command injection (P0 security).
78		if !strings.HasPrefix(rawURL, "http://") && !strings.HasPrefix(rawURL, "https://") {
79			return
80		}
81		switch runtime.GOOS {
82		case "darwin":
83			_ = exec.Command("open", rawURL).Start()
84		case "windows":
85			// On Windows, use 'cmd /c start "" <url>' — the empty "" is the window title
86			// parameter required by 'start' when the URL contains special characters.
87			_ = exec.Command("cmd", "/c", "start", "", rawURL).Start()
88		default:
89			_ = exec.Command("xdg-open", rawURL).Start()
90		}
91	}
