109				}
110				cmd.Print(buildInfoOutput(root))
111	
112				if openFlag {
113					openURL(repoURL)
114					cmd.Println("Opening in browser...")
115				} else {
116					cmd.Println("Run `drl info --open` to open in your browser.")
117				}
118				return nil
119			},
120		}
121		cmd.Flags().BoolVar(&jsonOut, "json", false, "output as JSON")
122		cmd.Flags().BoolVar(&openFlag, "open", false, "Open the repository page in your browser (ignored when --json is set)")
123		return cmd
124	}
