307	// formatInfoTelemetry returns the telemetry section content.
308	func formatInfoTelemetry(repoRoot string) string {
309		dbPath := filepath.Join(repoRoot, storage.DBPath)
310		if _, err := os.Stat(dbPath); os.IsNotExist(err) {
311			return "Telemetry: no data yet. Run `drl setup claude` to install hooks that collect telemetry.\n"
312		}
313	
314		db, err := storage.OpenRepoDB(repoRoot)
315		if err != nil {
316			return "Telemetry: no data yet. Run `drl setup claude` to install hooks that collect telemetry.\n"
317		}
318		defer db.Close()
319	
320		stats, err := telemetry.QueryStats(db)
321		if err != nil || stats.TotalEvents == 0 {
322			return "Telemetry: no data yet. Run `drl setup claude` to install hooks that collect telemetry.\n"
323		}
324	
325		var b strings.Builder
326		fmt.Fprintf(&b, "Total events: %d\n", stats.TotalEvents)
327		fmt.Fprintf(&b, "Retrievals: %d\n", stats.RetrievalCount)
328		if len(stats.HookStats) > 0 {
329			// Compute column width from longest hook name
330			nameWidth := len("Hook")
331			for _, hs := range stats.HookStats {
332				if len(hs.HookName) > nameWidth {
333					nameWidth = len(hs.HookName)
334				}
335			}
336			nameWidth += 2 // padding
337	
338			b.WriteString("\n")
339			fmt.Fprintf(&b, "%-*s %8s %10s\n", nameWidth, "Hook", "Count", "Avg (ms)")
340			fmt.Fprintf(&b, "%s\n", strings.Repeat("-", nameWidth+20))
341			for _, hs := range stats.HookStats {
342				fmt.Fprintf(&b, "%-*s %8d %10.1f\n", nameWidth, hs.HookName, hs.Count, hs.AvgDurationMs)
343			}
344		}
345		return b.String()
346	}
