349	func formatInfoLessons(repoRoot string) string {
350		result, err := memory.ReadItems(repoRoot)
351		if err != nil {
352			return "Lessons: 0 (no corpus found). Run `drl init` to set up the lesson index.\n"
353		}
354	
355		total := len(result.Items)
356		if total == 0 {
357			return "Lessons: 0. Get started with: `drl learn \"<insight>\"`\n"
358		}
359	
360		// Count by type
361		typeCounts := make(map[memory.ItemType]int)
362		lastCreated := ""
363		for _, item := range result.Items {
364			typeCounts[item.Type]++
365			if item.Created > lastCreated {
366				lastCreated = item.Created
367			}
368		}
369	
370		var b strings.Builder
371		fmt.Fprintf(&b, "Lessons: %d\n", total)
372	
373		if len(typeCounts) > 0 {
374			parts := make([]string, 0, len(typeCounts))
375			for typ, count := range typeCounts {
376				parts = append(parts, fmt.Sprintf("%s: %d", typ, count))
377			}
378			sort.Strings(parts)
379			fmt.Fprintf(&b, "  Types: %s\n", strings.Join(parts, ", "))
380		}
381	
382		if lastCreated != "" {
383			fmt.Fprintf(&b, "  Last captured: %s\n", datePrefix(lastCreated))
384		}
385	
386		return b.String()
387	}
