47	// initDirectories creates the .claude/ directory structure and index.jsonl.
48	func initDirectories(repoRoot string, result *InitResult) error {
49		dirs := []string{
50			filepath.Join(repoRoot, ".claude"),
51			filepath.Join(repoRoot, ".claude", "lessons"),
52			filepath.Join(repoRoot, ".claude", ".cache"),
53			filepath.Join(repoRoot, ".claude", "agents", "compound"),
54			filepath.Join(repoRoot, ".claude", "commands", "compound"),
55			filepath.Join(repoRoot, ".claude", "skills", "compound"),
56		}
57	
58		for _, dir := range dirs {
59			_, statErr := os.Stat(dir)
60			if err := os.MkdirAll(dir, 0755); err != nil {
61				return fmt.Errorf("create directory %s: %w", dir, err)
62			}
63			if os.IsNotExist(statErr) {
64				result.DirsCreated = append(result.DirsCreated, dir)
65			}
66		}
67	
68		indexPath := filepath.Join(repoRoot, ".claude", "lessons", "index.jsonl")
69		if _, err := os.Stat(indexPath); os.IsNotExist(err) {
70			if err := os.WriteFile(indexPath, []byte{}, 0644); err != nil {
71				return fmt.Errorf("create index.jsonl: %w", err)
72			}
73			result.FilesCreated = append(result.FilesCreated, indexPath)
74		}
75	
76		return EnsureGitignore(repoRoot)
77	}
