79	// initHooks installs or upgrades Claude Code hooks in settings.json.
80	func initHooks(repoRoot string, binaryPath string, result *InitResult) error {
81		settingsPath := filepath.Join(repoRoot, ".claude", "settings.json")
82		settings, err := ReadClaudeSettings(settingsPath)
83		if err != nil {
84			return fmt.Errorf("read settings: %w", err)
85		}
86	
87		needsInstall := !HasAllHooks(settings)
88		needsUpgrade := HooksNeedUpgrade(settings, binaryPath)
89		needsDedupe := HooksNeedDedupe(settings)
90	
91		if needsInstall || needsUpgrade || needsDedupe {
92			AddAllHooks(settings, binaryPath)
93			if err := WriteClaudeSettings(settingsPath, settings); err != nil {
94				return fmt.Errorf("write settings: %w", err)
95			}
96			result.HooksUpgraded = needsUpgrade && !needsInstall
97		}
98		result.HooksInstalled = true
99		return nil
100	}
