108	// resolveTier determines which tiers to install based on existing repo state and flags.
109	func resolveTier(existingRepo bool, opts InitOptions) tierConfig {
110		if opts.AllSkill {
111			return tierConfig{installCore: true, installStyle: true}
112		}
113		if opts.CoreSkill {
114			return tierConfig{installCore: true, installStyle: false}
115		}
116		if !existingRepo {
117			// Fresh repo: install everything
118			return tierConfig{installCore: true, installStyle: true}
119		}
120		// Existing repo with no flags: infrastructure only
121		return tierConfig{installCore: false, installStyle: false}
122	}
