124	// installTemplates installs all template assets (agents, commands, skills, docs).
125	// Detects the project stack to substitute quality gate placeholders.
126	func installTemplates(repoRoot string, tier tierConfig, result *InitResult) error {
127		version := build.Version
128	
129		updated, err := UpdateAgentsMd(repoRoot)
130		if err != nil {
131			return fmt.Errorf("update AGENTS.md: %w", err)
132		}
133		result.AgentsMdUpdated = updated
134	
135		updated, err = EnsureClaudeMdReference(repoRoot)
136		if err != nil {
137			return fmt.Errorf("ensure CLAUDE.md reference: %w", err)
138		}
139		result.ClaudeMdUpdated = updated
140	
141		created, pluginUpdated, err := CreatePluginManifest(repoRoot, version)
142		if err != nil {
143			return fmt.Errorf("create plugin.json: %w", err)
144		}
145		result.PluginCreated = created
146		result.PluginUpdated = pluginUpdated
147	
148		stack := DetectStack(repoRoot)
149		return installTemplateGroups(repoRoot, version, stack, tier, result)
