152	// installTemplateGroups installs agent, command, skill, role skill, and doc templates.
153	// Stack info is used to substitute quality gate placeholders in skills and docs.
154	// The tier config controls which groups are installed.
155	func installTemplateGroups(repoRoot string, version string, stack StackInfo, tier tierConfig, result *InitResult) error {
156		type installFunc struct {
157			fn   func() (int, int, error)
158			setN func(int)
159			setU func(int)
160			name string
161		}
162	
163		// Infrastructure tier: always installed
164		groups := []installFunc{
165			{func() (int, int, error) { return InstallWorkflowCommands(repoRoot) },
166				func(n int) { result.CommandsInstalled = n }, func(u int) { result.CommandsUpdated = u }, "workflow commands"},
167			{func() (int, int, error) { return InstallDocTemplates(repoRoot, version, stack) },
168				func(n int) { result.DocsInstalled = n }, func(u int) { result.DocsUpdated = u }, "doc templates"},
169			{func() (int, int, error) { return InstallResearchDocs(repoRoot) },
170				func(n int) { result.ResearchInstalled = n }, func(u int) { result.ResearchUpdated = u }, "research docs"},
171		}
172	
173		// Core tier: skills + agents
174		if tier.installCore {
175			groups = append(groups,
176				installFunc{func() (int, int, error) { return InstallAgentTemplates(repoRoot) },
177					func(n int) { result.AgentsInstalled = n }, func(u int) { result.AgentsUpdated = u }, "agent templates"},
178				installFunc{func() (int, int, error) { return InstallPhaseSkills(repoRoot, stack) },
179					func(n int) { result.SkillsInstalled = n }, func(u int) { result.SkillsUpdated = u }, "phase skills"},
180			)
181		}
182	
183		// Style tier: agent role skills
184		if tier.installStyle {
185			groups = append(groups,
186				installFunc{func() (int, int, error) { return InstallAgentRoleSkills(repoRoot) },
187					func(n int) { result.RoleSkillsInstalled = n }, func(u int) { result.RoleSkillsUpdated = u }, "agent role skills"},
188			)
189		}
190	
191		for _, g := range groups {
192			n, u, err := g.fn()
193			if err != nil {
194				return fmt.Errorf("install %s: %w", g.name, err)
195			}
196			g.setN(n)
197			g.setU(u)
198		}
199	
200		pruned, err := PruneStaleTemplates(repoRoot)
201		if err != nil {
202			return fmt.Errorf("prune stale templates: %w", err)
203		}
204		result.TemplatesPruned = pruned
205	
206		if err := CompileSkillsIndex(repoRoot); err != nil {
207			return fmt.Errorf("compile skills index: %w", err)
208		}
209		return nil
210	}
