212	// InitRepo initializes dark-research-lab in a repository.
213	// Creates .claude/ structure, lessons index, and optionally installs hooks.
214	// Tier behavior:
215	//   - No .claude/ + no flags: install all tiers
216	//   - Has .claude/ + no flags: infrastructure only (skip skills, agents, role skills)
217	//   - --core-skill: infrastructure + core skills/agents
218	//   - --all-skill: everything including style
219	func InitRepo(repoRoot string, opts InitOptions) (*InitResult, error) {
220		result := &InitResult{Success: true}
221	
222		// Detect existing repo BEFORE creating directories
223		_, statErr := os.Stat(filepath.Join(repoRoot, ".claude"))
224		existingRepo := statErr == nil
225	
226		tier := resolveTier(existingRepo, opts)
227	
228		if err := initDirectories(repoRoot, result); err != nil {
229			return nil, err
230		}
231	
232		if !opts.SkipHooks {
233			if err := initHooks(repoRoot, opts.BinaryPath, result); err != nil {
234				return nil, err
235			}
236		}
237	
238		if !opts.SkipTemplates {
239			if err := installTemplates(repoRoot, tier, result); err != nil {
240				return nil, err
241			}
242		}
243	
244		return result, nil
245	}
