247	// EnsureGitignore creates or updates .claude/.gitignore with required patterns.
248	func EnsureGitignore(repoRoot string) error {
249		gitignorePath := filepath.Join(repoRoot, ".claude", ".gitignore")
250	
251		// Ensure directory exists
252		if err := os.MkdirAll(filepath.Dir(gitignorePath), 0755); err != nil {
253			return err
254		}
255	
256		marker := "# drl managed"
257		patterns := marker + `
258	.cache/
259	*.sqlite
260	*.sqlite-shm
261	*.sqlite-wal
262	.drl-phase-state.json
263	.drl-failure-state.json
264	.drl-read-state.json
265	.drl-hints-shown
266	skills/compound/skills_index.json
267	`
268	
269		// If gitignore exists, check for our marker
270		existing, err := os.ReadFile(gitignorePath)
271		if err == nil {
272			if strings.Contains(string(existing), marker) {
273				return nil // Already has our patterns
274			}
275			// Append our patterns to existing content
276			combined := strings.TrimRight(string(existing), "\n") + "\n" + patterns
277			return os.WriteFile(gitignorePath, []byte(combined), 0644)
278		}
279		if !os.IsNotExist(err) {
280			return fmt.Errorf("read .gitignore: %w", err)
281		}
282	
283		return os.WriteFile(gitignorePath, []byte(patterns), 0644)
284	}
